//! I/O uses `Interpreter::io_file_slots` for raw `read`/`write`/`seek` alongside buffered handles.

/// TCP/UDP socket storage (high-level `std::net`, not raw POSIX).
pub(crate) enum PerlSocket {
    Listener(TcpListener),
    Stream(TcpStream),
    #[allow(dead_code)]
    Udp(UdpSocket),
}

