/// `minmax LIST` — returns [min, max] pair (Ruby's minmax).
fn builtin_minmax(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let xs = flatten_args(args);
    if xs.is_empty() {
        return Ok(PerlValue::array(vec![PerlValue::UNDEF, PerlValue::UNDEF]));
    }
    let mut min = xs[0].clone();
    let mut max = xs[0].clone();
    for x in xs.iter().skip(1) {
        if x.to_number() < min.to_number() {
            min = x.clone();
        }
        if x.to_number() > max.to_number() {
            max = x.clone();
        }
    }
    Ok(PerlValue::array(vec![min, max]))
}

/// `minmax_by FN, LIST` — returns [min, max] by key function (Ruby's minmax_by).
fn builtin_minmax_by(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![PerlValue::UNDEF, PerlValue::UNDEF]));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "minmax_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(PerlValue::array(vec![PerlValue::UNDEF, PerlValue::UNDEF]));
    }
    let mut min_item = xs[0].clone();
    let mut max_item = xs[0].clone();
    let mut min_key = exec_to_perl_result(
        interp.call_sub(&sub, vec![xs[0].clone()], WantarrayCtx::Scalar, line),
        "minmax_by",
        line,
    )?
    .to_number();
    let mut max_key = min_key;
    for x in xs.iter().skip(1) {
        let key = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "minmax_by",
            line,
        )?
        .to_number();
        if key < min_key {
            min_key = key;
            min_item = x.clone();
        }
        if key > max_key {
            max_key = key;
            max_item = x.clone();
        }
    }
    Ok(PerlValue::array(vec![min_item, max_item]))
}

/// `dig HASH, KEY1, KEY2, ...` — digs into nested structures (Ruby's dig).
fn builtin_dig(args: &[PerlValue]) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::UNDEF);
    }
    let mut current = args[0].clone();
    for key in args.iter().skip(1) {
        if let Some(m) = current.as_hash_map() {
            current = m.get(&key.to_string()).cloned().unwrap_or(PerlValue::UNDEF);
        } else if let Some(r) = current.as_hash_ref() {
            current = r
                .read()
                .get(&key.to_string())
                .cloned()
                .unwrap_or(PerlValue::UNDEF);
        } else if let Some(arr) = current.as_array_vec() {
            let idx = key.to_int();
            let idx = if idx < 0 { arr.len() as i64 + idx } else { idx } as usize;
            current = arr.get(idx).cloned().unwrap_or(PerlValue::UNDEF);
        } else if let Some(r) = current.as_array_ref() {
            let arr = r.read();
            let idx = key.to_int();
            let idx = if idx < 0 { arr.len() as i64 + idx } else { idx } as usize;
            current = arr.get(idx).cloned().unwrap_or(PerlValue::UNDEF);
        } else {
            return Ok(PerlValue::UNDEF);
        }
    }
    Ok(current)
}

/// `values_at COLL, IDX1, IDX2, ...` — returns values at given indices (Ruby's values_at).
fn builtin_values_at(args: &[PerlValue]) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let list = arg_to_vec(&args[0]);
    let indices: Vec<i64> = args[1..].iter().map(|v| v.to_int()).collect();
    let result: Vec<PerlValue> = indices
        .into_iter()
        .map(|idx| {
            let idx = if idx < 0 {
                list.len() as i64 + idx
            } else {
                idx
            } as usize;
            list.get(idx).cloned().unwrap_or(PerlValue::UNDEF)
        })
        .collect();
    Ok(PerlValue::array(result))
}

/// `fetch_val COLL, KEY [, DEFAULT]` — fetches value with optional default (Ruby's fetch).
fn builtin_fetch_val(args: &[PerlValue]) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::UNDEF);
    }
    let coll = args[0].clone();
    let key = args.get(1).cloned().unwrap_or(PerlValue::UNDEF);
    let default = args.get(2).cloned();
    let value = if let Some(m) = coll.as_hash_map() {
        m.get(&key.to_string()).cloned()
    } else if let Some(r) = coll.as_hash_ref() {
        r.read().get(&key.to_string()).cloned()
    } else {
        let list = arg_to_vec(&coll);
        let idx = key.to_int();
        let idx = if idx < 0 {
            list.len() as i64 + idx
        } else {
            idx
        } as usize;
        list.get(idx).cloned()
    };
    Ok(value.or(default).unwrap_or(PerlValue::UNDEF))
}

/// `slice_arr COLL, START, LEN` — returns slice of array (Ruby's slice).
fn builtin_slice_arr(args: &[PerlValue]) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let list = arg_to_vec(&args[0]);
    let start = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let start = if start < 0 {
        (list.len() as i64 + start).max(0)
    } else {
        start
    } as usize;
    let len = args
        .get(2)
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(list.len().saturating_sub(start));
    let end = (start + len).min(list.len());
    if start >= list.len() {
        return Ok(PerlValue::array(vec![]));
    }
    Ok(PerlValue::array(list[start..end].to_vec()))
}

/// `transform_keys FN, HASH` — transforms hash keys (Ruby's transform_keys).
fn builtin_transform_keys(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "transform_keys: first argument must be a code reference",
            line,
        ));
    };
    let hash = args.get(1).cloned().unwrap_or(PerlValue::UNDEF);
    let mut out: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    let pairs: Vec<(String, PerlValue)> = if let Some(m) = hash.as_hash_map() {
        m.iter().map(|(k, v)| (k.clone(), v.clone())).collect()
    } else if let Some(r) = hash.as_hash_ref() {
        r.read()
            .iter()
            .map(|(k, v)| (k.clone(), v.clone()))
            .collect()
    } else {
        vec![]
    };
    for (k, v) in pairs {
        let new_key = exec_to_perl_result(
            interp.call_sub(&sub, vec![PerlValue::string(k)], WantarrayCtx::Scalar, line),
            "transform_keys",
            line,
        )?
        .to_string();
        out.insert(new_key, v);
    }
    Ok(PerlValue::hash_ref(Arc::new(RwLock::new(out))))
}

/// `transform_values FN, HASH` — transforms hash values (Ruby's transform_values).
fn builtin_transform_values(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "transform_values: first argument must be a code reference",
            line,
        ));
    };
    let hash = args.get(1).cloned().unwrap_or(PerlValue::UNDEF);
    let mut out: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    let pairs: Vec<(String, PerlValue)> = if let Some(m) = hash.as_hash_map() {
        m.iter().map(|(k, v)| (k.clone(), v.clone())).collect()
    } else if let Some(r) = hash.as_hash_ref() {
        r.read()
            .iter()
            .map(|(k, v)| (k.clone(), v.clone()))
            .collect()
    } else {
        vec![]
    };
    for (k, v) in pairs {
        let new_val = exec_to_perl_result(
            interp.call_sub(&sub, vec![v], WantarrayCtx::Scalar, line),
            "transform_values",
            line,
        )?;
        out.insert(k, new_val);
    }
    Ok(PerlValue::hash_ref(Arc::new(RwLock::new(out))))
}

/// `sum_by FN, LIST` — sums values by key function (Ruby's sum with block).
fn builtin_sum_by(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::float(0.0));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "sum_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut sum = 0.0;
    for x in xs {
        let val = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::Scalar, line),
            "sum_by",
            line,
        )?;
        sum += val.to_number();
    }
    Ok(PerlValue::float(sum))
}

/// `uniq_by FN, LIST` — returns unique elements by key function (Ruby's uniq with block).
fn builtin_uniq_by(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "uniq_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut seen: std::collections::HashSet<String> = std::collections::HashSet::new();
    let mut result = Vec::new();
    for x in xs {
        let key = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "uniq_by",
            line,
        )?
        .to_string();
        if seen.insert(key) {
            result.push(x);
        }
    }
    Ok(PerlValue::array(result))
}

