/// `times_fn N, FN` — calls fn N times with index (Ruby's times).
fn builtin_times_fn(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    let n = args.first().map(|v| v.to_int().max(0)).unwrap_or(0);
    let f = args.get(1).cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "times_fn: second argument must be a code reference",
            line,
        ));
    };
    let mut result = Vec::with_capacity(n as usize);
    for i in 0..n {
        let val = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![PerlValue::integer(i)],
                WantarrayCtx::Scalar,
                line,
            ),
            "times_fn",
            line,
        )?;
        result.push(val);
    }
    Ok(PerlValue::array(result))
}

/// `step START, END, STEP` — generates range with step (Ruby's step).
fn builtin_step(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let start = args.first().map(|v| v.to_number()).unwrap_or(0.0);
    let end = args.get(1).map(|v| v.to_number()).unwrap_or(0.0);
    let step = args.get(2).map(|v| v.to_number()).unwrap_or(1.0);
    if step == 0.0 {
        return Ok(PerlValue::array(vec![]));
    }
    let mut result = Vec::new();
    let mut current = start;
    if step > 0.0 {
        while current <= end {
            result.push(PerlValue::float(current));
            current += step;
        }
    } else {
        while current >= end {
            result.push(PerlValue::float(current));
            current += step;
        }
    }
    Ok(PerlValue::array(result))
}

/// `upto START, END` — generates ascending range (Ruby's upto).
fn builtin_upto(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let start = args.first().map(|v| v.to_int()).unwrap_or(0);
    let end = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let result: Vec<PerlValue> = (start..=end).map(PerlValue::integer).collect();
    Ok(PerlValue::array(result))
}

/// `downto START, END` — generates descending range (Ruby's downto).
fn builtin_downto(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let start = args.first().map(|v| v.to_int()).unwrap_or(0);
    let end = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let result: Vec<PerlValue> = (end..=start).rev().map(PerlValue::integer).collect();
    Ok(PerlValue::array(result))
}

