/// `find_last FN, LIST` — returns last element matching predicate (JS Array.findLast).
fn builtin_find_last(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::UNDEF);
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "find_last: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    for x in xs.into_iter().rev() {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "find_last",
            line,
        )?;
        if result.is_true() {
            return Ok(x);
        }
    }
    Ok(PerlValue::UNDEF)
}

/// `find_last_index FN, LIST` — returns index of last matching element (JS Array.findLastIndex).
fn builtin_find_last_index(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::integer(-1));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "find_last_index: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    for (i, x) in xs.iter().enumerate().rev() {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "find_last_index",
            line,
        )?;
        if result.is_true() {
            return Ok(PerlValue::integer(i as i64));
        }
    }
    Ok(PerlValue::integer(-1))
}

/// `at_index LIST, INDEX` — returns element at index with negative support (JS Array.at).
fn builtin_at_index(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let list = arg_to_vec(&args.first().cloned().unwrap_or(PerlValue::UNDEF));
    let idx = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let idx = if idx < 0 {
        list.len() as i64 + idx
    } else {
        idx
    };
    if idx < 0 || idx as usize >= list.len() {
        return Ok(PerlValue::UNDEF);
    }
    Ok(list[idx as usize].clone())
}

/// `replace_at LIST, INDEX, VALUE` — returns new array with element replaced (JS Array.with).
fn builtin_replace_at(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let mut list = arg_to_vec(&args.first().cloned().unwrap_or(PerlValue::UNDEF));
    let idx = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let value = args.get(2).cloned().unwrap_or(PerlValue::UNDEF);
    let idx = if idx < 0 {
        list.len() as i64 + idx
    } else {
        idx
    };
    if idx >= 0 && (idx as usize) < list.len() {
        list[idx as usize] = value;
    }
    Ok(PerlValue::array(list))
}

/// `to_sorted FN, LIST` — returns new sorted array (JS Array.toSorted).
fn builtin_to_sorted(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    let (f, xs) = if args.first().and_then(|v| v.as_code_ref()).is_some() {
        let sub = args[0].as_code_ref().unwrap();
        (Some(sub), flatten_args(&args[1..]))
    } else {
        (None, flatten_args(args))
    };
    let mut result = xs;
    if let Some(sub) = f {
        result.sort_by(|a, b| {
            let cmp = interp.call_sub(&sub, vec![a.clone(), b.clone()], WantarrayCtx::Scalar, line);
            match cmp {
                Ok(v) => {
                    let n = v.to_int();
                    n.cmp(&0)
                }
                _ => std::cmp::Ordering::Equal,
            }
        });
    } else {
        result.sort_by_key(|a| a.to_string());
    }
    Ok(PerlValue::array(result))
}

/// `to_reversed LIST` — returns new reversed array (JS Array.toReversed).
fn builtin_to_reversed(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let mut xs = flatten_args(args);
    xs.reverse();
    Ok(PerlValue::array(xs))
}

/// `to_spliced LIST, START, DELETE_COUNT, ITEMS...` — returns new array with splice applied (JS Array.toSpliced).
fn builtin_to_spliced(args: &[PerlValue]) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let mut list = arg_to_vec(&args[0]);
    let start = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let start = if start < 0 {
        (list.len() as i64 + start).max(0)
    } else {
        start
    } as usize;
    let delete_count = args.get(2).map(|v| v.to_int().max(0) as usize).unwrap_or(0);
    let items: Vec<PerlValue> = args.get(3..).map(|s| s.to_vec()).unwrap_or_default();
    let end = (start + delete_count).min(list.len());
    list.splice(start..end, items);
    Ok(PerlValue::array(list))
}

/// `flat_depth DEPTH, LIST` — flattens array to specified depth (JS Array.flat).
fn builtin_flat_depth(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let depth = args
        .first()
        .map(|v| v.to_int().max(0) as usize)
        .unwrap_or(1);
    let xs = args.get(1..).map(|s| s.to_vec()).unwrap_or_default();
    fn flatten_to_depth(items: Vec<PerlValue>, depth: usize) -> Vec<PerlValue> {
        if depth == 0 {
            return items;
        }
        let mut result = Vec::new();
        for item in items {
            if let Some(r) = item.as_array_ref() {
                result.extend(flatten_to_depth(r.read().clone(), depth - 1));
            } else if let Some(arr) = item.as_array_vec() {
                result.extend(flatten_to_depth(arr, depth - 1));
            } else {
                result.push(item);
            }
        }
        result
    }
    Ok(PerlValue::array(flatten_to_depth(xs, depth)))
}

/// `fill_arr VALUE, START, END, LIST` — fills array with value (JS Array.fill).
fn builtin_fill_arr(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let value = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let start = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let end = args.get(2).map(|v| v.to_int());
    let mut list = flatten_args(&args[3..]);
    let len = list.len() as i64;
    let start = if start < 0 {
        (len + start).max(0)
    } else {
        start.min(len)
    } as usize;
    let end = end
        .map(|e| if e < 0 { (len + e).max(0) } else { e.min(len) } as usize)
        .unwrap_or(list.len());
    for i in start..end.min(list.len()) {
        list[i] = value.clone();
    }
    Ok(PerlValue::array(list))
}

/// `includes_val LIST, VALUE` — checks if array includes value (JS Array.includes).
fn builtin_includes_val(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let list = arg_to_vec(&args.first().cloned().unwrap_or(PerlValue::UNDEF));
    let value = args.get(1).cloned().unwrap_or(PerlValue::UNDEF);
    let value_str = value.to_string();
    for item in list {
        if item.to_string() == value_str {
            return Ok(bool_iv(true));
        }
    }
    Ok(bool_iv(false))
}

/// `object_keys HASH` — returns keys of hash (JS Object.keys).
fn builtin_object_keys(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let hash = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let keys: Vec<PerlValue> = if let Some(m) = hash.as_hash_map() {
        m.keys().map(|k| PerlValue::string(k.clone())).collect()
    } else if let Some(r) = hash.as_hash_ref() {
        r.read()
            .keys()
            .map(|k| PerlValue::string(k.clone()))
            .collect()
    } else {
        vec![]
    };
    Ok(PerlValue::array(keys))
}

/// `object_values HASH` — returns values of hash (JS Object.values).
fn builtin_object_values(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let hash = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let values: Vec<PerlValue> = if let Some(m) = hash.as_hash_map() {
        m.values().cloned().collect()
    } else if let Some(r) = hash.as_hash_ref() {
        r.read().values().cloned().collect()
    } else {
        vec![]
    };
    Ok(PerlValue::array(values))
}

/// `object_entries HASH` — returns [key, value] pairs (JS Object.entries).
fn builtin_object_entries(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let hash = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let entries: Vec<PerlValue> = if let Some(m) = hash.as_hash_map() {
        m.iter()
            .map(|(k, v)| PerlValue::array(vec![PerlValue::string(k.clone()), v.clone()]))
            .collect()
    } else if let Some(r) = hash.as_hash_ref() {
        r.read()
            .iter()
            .map(|(k, v)| PerlValue::array(vec![PerlValue::string(k.clone()), v.clone()]))
            .collect()
    } else {
        vec![]
    };
    Ok(PerlValue::array(entries))
}

/// `object_from_entries PAIRS` — creates hash from [key, value] pairs (JS Object.fromEntries).
fn builtin_object_from_entries(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let pairs = flatten_args(args);
    let mut out: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    for pair in pairs {
        let list = arg_to_vec(&pair);
        if list.len() >= 2 {
            out.insert(list[0].to_string(), list[1].clone());
        }
    }
    Ok(PerlValue::hash_ref(Arc::new(RwLock::new(out))))
}

