/// `inspect FN, LIST` — calls fn on each element but returns original list (Rust's inspect).
fn builtin_inspect(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "inspect: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    for x in &xs {
        let _ = interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Void, line);
    }
    Ok(PerlValue::array(xs))
}

