/// `tally_by FN, LIST` — counts elements by key function (Ruby's tally with block).
fn builtin_tally_by(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "tally_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut counts: indexmap::IndexMap<String, i64> = indexmap::IndexMap::new();
    for x in xs {
        let key = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::Scalar, line),
            "tally_by",
            line,
        )?
        .to_string();
        *counts.entry(key).or_insert(0) += 1;
    }
    let out: indexmap::IndexMap<String, PerlValue> = counts
        .into_iter()
        .map(|(k, v)| (k, PerlValue::integer(v)))
        .collect();
    Ok(PerlValue::hash_ref(Arc::new(RwLock::new(out))))
}

/// `sole LIST` — returns element if list has exactly one, else error (Ruby's sole).
fn builtin_sole(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let xs = flatten_args(args);
    if xs.len() != 1 {
        return Err(PerlError::runtime(
            format!("sole: expected exactly one element, got {}", xs.len()),
            line,
        ));
    }
    Ok(xs.into_iter().next().unwrap())
}

/// `chunk_while FN, LIST` — chunks consecutive elements while predicate is true (Ruby's chunk_while).
fn builtin_chunk_while(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "chunk_while: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    if xs.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let mut result: Vec<PerlValue> = Vec::new();
    let mut current_chunk: Vec<PerlValue> = vec![xs[0].clone()];
    for i in 1..xs.len() {
        let prev = &xs[i - 1];
        let curr = &xs[i];
        let should_continue = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![prev.clone(), curr.clone()],
                WantarrayCtx::Scalar,
                line,
            ),
            "chunk_while",
            line,
        )?
        .is_true();
        if should_continue {
            current_chunk.push(curr.clone());
        } else {
            result.push(PerlValue::array_ref(Arc::new(RwLock::new(std::mem::take(
                &mut current_chunk,
            )))));
            current_chunk.push(curr.clone());
        }
    }
    if !current_chunk.is_empty() {
        result.push(PerlValue::array_ref(Arc::new(RwLock::new(current_chunk))));
    }
    Ok(PerlValue::array(result))
}

/// `count_while FN, LIST` — counts elements while predicate is true.
fn builtin_count_while(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::integer(0));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "count_while: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut count = 0i64;
    for x in xs {
        let result = exec_to_perl_result(
            interp.call_sub(&sub, vec![x], WantarrayCtx::Scalar, line),
            "count_while",
            line,
        )?;
        if !result.is_true() {
            break;
        }
        count += 1;
    }
    Ok(PerlValue::integer(count))
}

