/// `insert_at LIST, INDEX, VALUE` — returns new list with value inserted at index.
fn builtin_insert_at(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let mut list = arg_to_vec(&args.first().cloned().unwrap_or(PerlValue::UNDEF));
    let idx = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let value = args.get(2).cloned().unwrap_or(PerlValue::UNDEF);
    let idx = if idx < 0 {
        (list.len() as i64 + idx + 1).max(0)
    } else {
        idx
    } as usize;
    let idx = idx.min(list.len());
    list.insert(idx, value);
    Ok(PerlValue::array(list))
}

/// `delete_at LIST, INDEX` — returns new list with element at index removed.
fn builtin_delete_at(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let mut list = arg_to_vec(&args.first().cloned().unwrap_or(PerlValue::UNDEF));
    let idx = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    let idx = if idx < 0 {
        list.len() as i64 + idx
    } else {
        idx
    };
    if idx >= 0 && (idx as usize) < list.len() {
        list.remove(idx as usize);
    }
    Ok(PerlValue::array(list))
}

/// `update_at FN, LIST, INDEX` — returns new list with element at index updated by function.
fn builtin_update_at(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "update_at: first argument must be a code reference",
            line,
        ));
    };
    let mut list = arg_to_vec(&args.get(1).cloned().unwrap_or(PerlValue::UNDEF));
    let idx = args.get(2).map(|v| v.to_int()).unwrap_or(0);
    let idx = if idx < 0 {
        list.len() as i64 + idx
    } else {
        idx
    };
    if idx >= 0 && (idx as usize) < list.len() {
        let new_val = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![list[idx as usize].clone()],
                WantarrayCtx::Scalar,
                line,
            ),
            "update_at",
            line,
        )?;
        list[idx as usize] = new_val;
    }
    Ok(PerlValue::array(list))
}

/// `split_on VALUE, LIST` — splits list on delimiter value.
fn builtin_split_on(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let delimiter = args.first().map(|v| v.to_string()).unwrap_or_default();
    let xs = flatten_args(&args[1..]);
    let mut result: Vec<PerlValue> = Vec::new();
    let mut current: Vec<PerlValue> = Vec::new();
    for x in xs {
        if x.to_string() == delimiter {
            result.push(PerlValue::array(std::mem::take(&mut current)));
        } else {
            current.push(x);
        }
    }
    result.push(PerlValue::array(current));
    Ok(PerlValue::array(result))
}

/// `words_from STR` — splits string into words.
fn builtin_words_from(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let words: Vec<PerlValue> = s
        .split_whitespace()
        .map(|w| PerlValue::string(w.to_string()))
        .collect();
    Ok(PerlValue::array(words))
}

/// `unwords LIST` — joins words with spaces.
fn builtin_unwords(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let xs = flatten_args(args);
    let s: String = xs
        .iter()
        .map(|x| x.to_string())
        .collect::<Vec<_>>()
        .join(" ");
    Ok(PerlValue::string(s))
}

/// `lines_from STR` — splits string into lines.
fn builtin_lines_from(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let lines: Vec<PerlValue> = s
        .lines()
        .map(|l| PerlValue::string(l.to_string()))
        .collect();
    Ok(PerlValue::array(lines))
}

/// `unlines LIST` — joins lines with newlines.
fn builtin_unlines(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let xs = flatten_args(args);
    let s: String = xs
        .iter()
        .map(|x| x.to_string())
        .collect::<Vec<_>>()
        .join("\n");
    Ok(PerlValue::string(s))
}

/// `window_n N, LIST` — returns sliding windows of size N.
fn builtin_window_n(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(2);
    let xs = flatten_args(&args[1..]);
    if xs.len() < n {
        return Ok(PerlValue::array(vec![]));
    }
    let result: Vec<PerlValue> = xs
        .windows(n)
        .map(|w| PerlValue::array_ref(Arc::new(RwLock::new(w.to_vec()))))
        .collect();
    Ok(PerlValue::array(result))
}

/// `adjacent_pairs LIST` — returns adjacent pairs as 2-tuples.
fn builtin_adjacent_pairs(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let xs = flatten_args(args);
    if xs.len() < 2 {
        return Ok(PerlValue::array(vec![]));
    }
    let result: Vec<PerlValue> = xs
        .windows(2)
        .map(|w| PerlValue::array_ref(Arc::new(RwLock::new(w.to_vec()))))
        .collect();
    Ok(PerlValue::array(result))
}

/// `zip_all LISTS...` — zips multiple lists, truncating to shortest.
fn builtin_zip_all(args: &[PerlValue]) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let lists: Vec<Vec<PerlValue>> = args.iter().map(arg_to_vec).collect();
    let min_len = lists.iter().map(|l| l.len()).min().unwrap_or(0);
    let mut result = Vec::with_capacity(min_len);
    for i in 0..min_len {
        let tuple: Vec<PerlValue> = lists.iter().map(|l| l[i].clone()).collect();
        result.push(PerlValue::array_ref(Arc::new(RwLock::new(tuple))));
    }
    Ok(PerlValue::array(result))
}

/// `unzip_pairs PAIRS` — unzips list of pairs into two lists.
fn builtin_unzip_pairs(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let pairs = flatten_args(args);
    let mut firsts = Vec::new();
    let mut seconds = Vec::new();
    for pair in pairs {
        let list = arg_to_vec(&pair);
        firsts.push(list.first().cloned().unwrap_or(PerlValue::UNDEF));
        seconds.push(list.get(1).cloned().unwrap_or(PerlValue::UNDEF));
    }
    Ok(PerlValue::array(vec![
        PerlValue::array_ref(Arc::new(RwLock::new(firsts))),
        PerlValue::array_ref(Arc::new(RwLock::new(seconds))),
    ]))
}

/// `interpose SEP, LIST` — alias for intersperse.
fn builtin_interpose(args: &[PerlValue]) -> PerlResult<PerlValue> {
    builtin_intersperse_val(args)
}

/// `partition_n N, LIST` — partitions list into groups of N (last may be smaller).
fn builtin_partition_n(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let n = args
        .first()
        .map(|v| v.to_int().max(1) as usize)
        .unwrap_or(1);
    let xs = flatten_args(&args[1..]);
    let result: Vec<PerlValue> = xs
        .chunks(n)
        .map(|chunk| PerlValue::array_ref(Arc::new(RwLock::new(chunk.to_vec()))))
        .collect();
    Ok(PerlValue::array(result))
}

/// `map_indexed FN, LIST` — maps with index as second argument.
fn builtin_map_indexed(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "map_indexed: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut result = Vec::with_capacity(xs.len());
    for (i, x) in xs.into_iter().enumerate() {
        let mapped = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![x, PerlValue::integer(i as i64)],
                WantarrayCtx::Scalar,
                line,
            ),
            "map_indexed",
            line,
        )?;
        result.push(mapped);
    }
    Ok(PerlValue::array(result))
}

/// `reduce_indexed FN, INIT, LIST` — reduce with index as third argument.
fn builtin_reduce_indexed(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::UNDEF);
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "reduce_indexed: first argument must be a code reference",
            line,
        ));
    };
    let mut acc = args.get(1).cloned().unwrap_or(PerlValue::UNDEF);
    let xs = flatten_args(&args[2..]);
    for (i, x) in xs.into_iter().enumerate() {
        acc = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![acc, x, PerlValue::integer(i as i64)],
                WantarrayCtx::Scalar,
                line,
            ),
            "reduce_indexed",
            line,
        )?;
    }
    Ok(acc)
}

/// `filter_indexed FN, LIST` — filter with index as second argument.
fn builtin_filter_indexed(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::array(vec![]));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "filter_indexed: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut result = Vec::new();
    for (i, x) in xs.into_iter().enumerate() {
        let keep = exec_to_perl_result(
            interp.call_sub(
                &sub,
                vec![x.clone(), PerlValue::integer(i as i64)],
                WantarrayCtx::Scalar,
                line,
            ),
            "filter_indexed",
            line,
        )?
        .is_true();
        if keep {
            result.push(x);
        }
    }
    Ok(PerlValue::array(result))
}

/// `group_by_fn FN, LIST` — groups elements by key function result.
fn builtin_group_by_fn(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "group_by_fn: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut groups: indexmap::IndexMap<String, Vec<PerlValue>> = indexmap::IndexMap::new();
    for x in xs {
        let key = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "group_by_fn",
            line,
        )?
        .to_string();
        groups.entry(key).or_default().push(x);
    }
    let out: indexmap::IndexMap<String, PerlValue> = groups
        .into_iter()
        .map(|(k, v)| (k, PerlValue::array_ref(Arc::new(RwLock::new(v)))))
        .collect();
    Ok(PerlValue::hash_ref(Arc::new(RwLock::new(out))))
}

/// `index_by FN, LIST` — creates hash indexed by key function result.
fn builtin_index_by(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "index_by: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut out: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    for x in xs {
        let key = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "index_by",
            line,
        )?
        .to_string();
        out.insert(key, x);
    }
    Ok(PerlValue::hash_ref(Arc::new(RwLock::new(out))))
}

/// `associate FN, LIST` — creates hash with elements as keys and fn results as values.
fn builtin_associate(
    interp: &mut Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    if args.is_empty() {
        return Ok(PerlValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    let f = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    let Some(sub) = f.as_code_ref() else {
        return Err(PerlError::runtime(
            "associate: first argument must be a code reference",
            line,
        ));
    };
    let xs = flatten_args(&args[1..]);
    let mut out: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    for x in xs {
        let value = exec_to_perl_result(
            interp.call_sub(&sub, vec![x.clone()], WantarrayCtx::Scalar, line),
            "associate",
            line,
        )?;
        out.insert(x.to_string(), value);
    }
    Ok(PerlValue::hash_ref(Arc::new(RwLock::new(out))))
}

