/// `add_days DATE, N` — add N days to Unix timestamp.
fn builtin_add_days(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    let days = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(PerlValue::integer(ts + days * 86400))
}

/// `add_hours DATE, N` — add N hours to Unix timestamp.
fn builtin_add_hours(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    let hours = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(PerlValue::integer(ts + hours * 3600))
}

/// `add_minutes DATE, N` — add N minutes to Unix timestamp.
fn builtin_add_minutes(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    let mins = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(PerlValue::integer(ts + mins * 60))
}

/// `diff_days DATE1, DATE2` — difference in days.
fn builtin_diff_days(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let ts1 = args.first().map(|v| v.to_int()).unwrap_or(0);
    let ts2 = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(PerlValue::integer((ts2 - ts1) / 86400))
}

/// `diff_hours DATE1, DATE2` — difference in hours.
fn builtin_diff_hours(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let ts1 = args.first().map(|v| v.to_int()).unwrap_or(0);
    let ts2 = args.get(1).map(|v| v.to_int()).unwrap_or(0);
    Ok(PerlValue::integer((ts2 - ts1) / 3600))
}

/// `start_of_day TS` — returns timestamp at start of day.
fn builtin_start_of_day(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    Ok(PerlValue::integer(ts - (ts % 86400)))
}

/// `end_of_day TS` — returns timestamp at end of day.
fn builtin_end_of_day(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    Ok(PerlValue::integer(ts - (ts % 86400) + 86399))
}

/// `start_of_hour TS` — returns timestamp at start of hour.
fn builtin_start_of_hour(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    Ok(PerlValue::integer(ts - (ts % 3600)))
}

/// `start_of_minute TS` — returns timestamp at start of minute.
fn builtin_start_of_minute(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let ts = args.first().map(|v| v.to_int()).unwrap_or(0);
    Ok(PerlValue::integer(ts - (ts % 60)))
}

// ── dateutils-style builtins ────────────────────────────────────────────

/// Parse a date string (ISO 8601 or common formats) into a chrono NaiveDateTime.
fn parse_date_flexible(s: &str) -> Option<chrono::NaiveDateTime> {
    use chrono::NaiveDate;
    use chrono::NaiveDateTime;
    // Try ISO 8601 with T separator
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S") {
        return Some(dt);
    }
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S%.f") {
        return Some(dt);
    }
    // Space separator
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%d %H:%M:%S") {
        return Some(dt);
    }
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%d %H:%M:%S%.f") {
        return Some(dt);
    }
    if let Ok(dt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%d %H:%M") {
        return Some(dt);
    }
    // Date only
    if let Ok(d) = NaiveDate::parse_from_str(s, "%Y-%m-%d") {
        return Some(d.and_hms_opt(0, 0, 0).unwrap());
    }
    if let Ok(d) = NaiveDate::parse_from_str(s, "%Y/%m/%d") {
        return Some(d.and_hms_opt(0, 0, 0).unwrap());
    }
    if let Ok(d) = NaiveDate::parse_from_str(s, "%m/%d/%Y") {
        return Some(d.and_hms_opt(0, 0, 0).unwrap());
    }
    if let Ok(d) = NaiveDate::parse_from_str(s, "%d-%b-%Y") {
        return Some(d.and_hms_opt(0, 0, 0).unwrap());
    }
    // Epoch integer/float
    if let Ok(epoch) = s.parse::<f64>() {
        return chrono::DateTime::from_timestamp(epoch as i64, 0).map(|dt| dt.naive_utc());
    }
    None
}

type DurationPattern = (&'static str, fn(i64) -> chrono::Duration);

/// Parse a duration string: "1d", "2w", "3h", "30m", "1y", "1mo", "1 week", etc.
fn parse_duration_str(s: &str) -> Option<chrono::Duration> {
    let s = s.trim().to_lowercase();
    // Try formats like "1d", "2w", "3h", "30m", "5s", "1y", "1mo"
    let re_patterns: &[DurationPattern] = &[
        ("seconds", |n| chrono::Duration::seconds(n)),
        ("second", |n| chrono::Duration::seconds(n)),
        ("secs", |n| chrono::Duration::seconds(n)),
        ("sec", |n| chrono::Duration::seconds(n)),
        ("minutes", |n| chrono::Duration::minutes(n)),
        ("minute", |n| chrono::Duration::minutes(n)),
        ("mins", |n| chrono::Duration::minutes(n)),
        ("min", |n| chrono::Duration::minutes(n)),
        ("hours", |n| chrono::Duration::hours(n)),
        ("hour", |n| chrono::Duration::hours(n)),
        ("hrs", |n| chrono::Duration::hours(n)),
        ("hr", |n| chrono::Duration::hours(n)),
        ("days", |n| chrono::Duration::days(n)),
        ("day", |n| chrono::Duration::days(n)),
        ("weeks", |n| chrono::Duration::weeks(n)),
        ("week", |n| chrono::Duration::weeks(n)),
        ("months", |n| chrono::Duration::days(n * 30)),
        ("month", |n| chrono::Duration::days(n * 30)),
        ("years", |n| chrono::Duration::days(n * 365)),
        ("year", |n| chrono::Duration::days(n * 365)),
    ];
    for &(suffix, f) in re_patterns {
        if let Some(num_str) = s.strip_suffix(suffix) {
            if let Ok(n) = num_str.trim().parse::<i64>() {
                return Some(f(n));
            }
        }
    }
    // Short suffixes: "1d", "2w", "3h", "30m", "5s", "1y"
    if s.len() >= 2 {
        let (num_str, unit) = s.split_at(s.len() - 1);
        if let Ok(n) = num_str.trim().parse::<i64>() {
            return match unit {
                "s" => Some(chrono::Duration::seconds(n)),
                "m" => Some(chrono::Duration::minutes(n)),
                "h" => Some(chrono::Duration::hours(n)),
                "d" => Some(chrono::Duration::days(n)),
                "w" => Some(chrono::Duration::weeks(n)),
                "y" => Some(chrono::Duration::days(n * 365)),
                _ => None,
            };
        }
        // "1mo"
        if s.len() >= 3 {
            let (num_str2, unit2) = s.split_at(s.len() - 2);
            if unit2 == "mo" {
                if let Ok(n) = num_str2.trim().parse::<i64>() {
                    return Some(chrono::Duration::days(n * 30));
                }
            }
        }
    }
    None
}

/// `dateseq START, END [, STEP]` — generate sequence of date strings.
/// Returns an array of ISO date strings. STEP defaults to "1d".
/// Example: `dateseq("2024-01-01", "2024-01-07")` → 7 dates
/// Example: `dateseq("2024-01-01", "2024-12-31", "1w")` → weekly dates
fn builtin_dateseq(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let start_str = args.first().map(|v| v.to_string()).unwrap_or_default();
    let end_str = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    let step_str = args
        .get(2)
        .map(|v| v.to_string())
        .unwrap_or_else(|| "1d".to_string());
    let start = parse_date_flexible(&start_str).ok_or_else(|| {
        PerlError::runtime(
            format!("dateseq: cannot parse start date: {}", start_str),
            line,
        )
    })?;
    let end = parse_date_flexible(&end_str).ok_or_else(|| {
        PerlError::runtime(format!("dateseq: cannot parse end date: {}", end_str), line)
    })?;
    let step = parse_duration_str(&step_str).ok_or_else(|| {
        PerlError::runtime(format!("dateseq: cannot parse step: {}", step_str), line)
    })?;
    if step.num_seconds() == 0 {
        return Err(PerlError::runtime("dateseq: step cannot be zero", line));
    }
    let mut result = Vec::new();
    let mut cur = start;
    let forward = end >= start;
    let max_items = 100_000; // safety limit
    while (forward && cur <= end) || (!forward && cur >= end) {
        let fmt = if cur.time() == chrono::NaiveTime::from_hms_opt(0, 0, 0).unwrap() {
            cur.format("%Y-%m-%d").to_string()
        } else {
            cur.format("%Y-%m-%d %H:%M:%S").to_string()
        };
        result.push(PerlValue::string(fmt));
        if result.len() >= max_items {
            break;
        }
        cur += step;
    }
    Ok(PerlValue::array(result))
}

/// `dategrep PATTERN, LIST` — filter strings containing dates matching pattern.
/// PATTERN is a date string or glob-like: "2024-03-*", "2024-*", "2024-03-15".
/// Scans each line for ISO-ish dates and checks if they match the pattern.
fn builtin_dategrep(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let pattern = args.first().map(|v| v.to_string()).unwrap_or_default();
    let list = if args.len() > 1 {
        args[1..]
            .iter()
            .flat_map(|v| {
                let items = v.to_list();
                if items.is_empty() {
                    vec![v.clone()]
                } else {
                    items
                }
            })
            .collect::<Vec<_>>()
    } else {
        // Use $_ if no list given
        vec![interp.scope.get_scalar("_")]
    };
    // Convert glob pattern to regex: "2024-03-*" → "2024-03-\d+"
    let re_pat = pattern.replace('.', r"\.").replace('*', r"\d+");
    let re = regex::Regex::new(&re_pat).unwrap_or_else(|_| regex::Regex::new("^$").unwrap());
    let mut result = Vec::new();
    for item in list {
        let s = item.to_string();
        if re.is_match(&s) {
            result.push(item);
        }
    }
    Ok(PerlValue::array(result))
}

/// `dateround DATE, UNIT` — round a date to the nearest unit.
/// UNIT: "second", "minute", "hour", "day", "week", "month", "year"
/// Example: `dateround("2024-03-15 14:37:22", "hour")` → "2024-03-15 15:00:00"
fn builtin_dateround(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    use chrono::{Datelike, NaiveDate, Timelike};
    let date_str = args.first().map(|v| v.to_string()).unwrap_or_default();
    let unit = args
        .get(1)
        .map(|v| v.to_string())
        .unwrap_or_else(|| "day".to_string());
    let dt = parse_date_flexible(&date_str).ok_or_else(|| {
        PerlError::runtime(format!("dateround: cannot parse: {}", date_str), line)
    })?;
    let rounded = match unit.as_str() {
        "second" | "sec" | "s" => dt.with_nanosecond(0).unwrap_or(dt),
        "minute" | "min" | "m" => {
            let base = dt
                .with_second(0)
                .and_then(|d| d.with_nanosecond(0))
                .unwrap_or(dt);
            if dt.second() >= 30 {
                base + chrono::Duration::minutes(1)
            } else {
                base
            }
        }
        "hour" | "hr" | "h" => {
            let base = dt
                .with_minute(0)
                .and_then(|d| d.with_second(0))
                .and_then(|d| d.with_nanosecond(0))
                .unwrap_or(dt);
            if dt.minute() >= 30 {
                base + chrono::Duration::hours(1)
            } else {
                base
            }
        }
        "day" | "d" => {
            let base = NaiveDate::from_ymd_opt(dt.year(), dt.month(), dt.day())
                .unwrap()
                .and_hms_opt(0, 0, 0)
                .unwrap();
            if dt.hour() >= 12 {
                base + chrono::Duration::days(1)
            } else {
                base
            }
        }
        "week" | "w" => {
            let weekday = dt.weekday().num_days_from_monday() as i64;
            let start = dt.date() - chrono::Duration::days(weekday);
            let base = start.and_hms_opt(0, 0, 0).unwrap();
            if weekday >= 4 {
                base + chrono::Duration::weeks(1)
            } else {
                base
            }
        }
        "month" | "mo" => {
            let base = NaiveDate::from_ymd_opt(dt.year(), dt.month(), 1)
                .unwrap()
                .and_hms_opt(0, 0, 0)
                .unwrap();
            if dt.day() >= 15 {
                let (y, m) = if dt.month() == 12 {
                    (dt.year() + 1, 1)
                } else {
                    (dt.year(), dt.month() + 1)
                };
                NaiveDate::from_ymd_opt(y, m, 1)
                    .unwrap()
                    .and_hms_opt(0, 0, 0)
                    .unwrap()
            } else {
                base
            }
        }
        "year" | "y" => {
            let base = NaiveDate::from_ymd_opt(dt.year(), 1, 1)
                .unwrap()
                .and_hms_opt(0, 0, 0)
                .unwrap();
            if dt.month() >= 7 {
                NaiveDate::from_ymd_opt(dt.year() + 1, 1, 1)
                    .unwrap()
                    .and_hms_opt(0, 0, 0)
                    .unwrap()
            } else {
                base
            }
        }
        _ => {
            return Err(PerlError::runtime(
                format!("dateround: unknown unit: {}", unit),
                line,
            ))
        }
    };
    let fmt = if rounded.time() == chrono::NaiveTime::from_hms_opt(0, 0, 0).unwrap() {
        rounded.format("%Y-%m-%d").to_string()
    } else {
        rounded.format("%Y-%m-%d %H:%M:%S").to_string()
    };
    Ok(PerlValue::string(fmt))
}

/// `datesort LIST` — sort strings chronologically by detected date.
/// Parses each string for an ISO-ish date and sorts by it.
fn builtin_datesort(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let mut items: Vec<PerlValue> = args
        .iter()
        .flat_map(|v| {
            let list = v.to_list();
            if list.is_empty() {
                vec![v.clone()]
            } else {
                list
            }
        })
        .collect();
    items.sort_by(|a, b| {
        let da = parse_date_flexible(&a.to_string());
        let db = parse_date_flexible(&b.to_string());
        match (da, db) {
            (Some(a), Some(b)) => a.cmp(&b),
            (Some(_), None) => std::cmp::Ordering::Less,
            (None, Some(_)) => std::cmp::Ordering::Greater,
            (None, None) => a.to_string().cmp(&b.to_string()),
        }
    });
    Ok(PerlValue::array(items))
}

// ─────────────────────────────────────────────────────────────────────────
// Extended stdlib: Encoding/Hashing
// ─────────────────────────────────────────────────────────────────────────

/// `url_encode STR` — URL encode string.
fn builtin_url_encode(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let encoded: String = s
        .bytes()
        .map(|b| {
            if b.is_ascii_alphanumeric() || b == b'-' || b == b'_' || b == b'.' || b == b'~' {
                format!("{}", b as char)
            } else {
                format!("%{:02X}", b)
            }
        })
        .collect();
    Ok(PerlValue::string(encoded))
}

/// `url_decode STR` — URL decode string.
fn builtin_url_decode(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let mut result = Vec::new();
    let bytes = s.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        if bytes[i] == b'%' && i + 2 < bytes.len() {
            if let Ok(byte) = u8::from_str_radix(&s[i + 1..i + 3], 16) {
                result.push(byte);
                i += 3;
                continue;
            }
        }
        if bytes[i] == b'+' {
            result.push(b' ');
        } else {
            result.push(bytes[i]);
        }
        i += 1;
    }
    Ok(PerlValue::string(
        String::from_utf8_lossy(&result).to_string(),
    ))
}

/// `html_encode STR` — HTML encode string.
fn builtin_html_encode(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let encoded: String = s
        .chars()
        .map(|c| match c {
            '&' => "&amp;".to_string(),
            '<' => "&lt;".to_string(),
            '>' => "&gt;".to_string(),
            '"' => "&quot;".to_string(),
            '\'' => "&#x27;".to_string(),
            _ => c.to_string(),
        })
        .collect();
    Ok(PerlValue::string(encoded))
}

/// `html_decode STR` — HTML decode string.
fn builtin_html_decode(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let decoded = s
        .replace("&amp;", "&")
        .replace("&lt;", "<")
        .replace("&gt;", ">")
        .replace("&quot;", "\"")
        .replace("&#x27;", "'")
        .replace("&#39;", "'")
        .replace("&nbsp;", " ");
    Ok(PerlValue::string(decoded))
}

/// `adler32 STR` — Adler32 checksum.
fn builtin_adler32(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let mut a: u32 = 1;
    let mut b: u32 = 0;
    for byte in s.bytes() {
        a = (a + byte as u32) % 65521;
        b = (b + a) % 65521;
    }
    Ok(PerlValue::integer(((b << 16) | a) as i64))
}

/// `fnv1a STR` — FNV-1a hash.
fn builtin_fnv1a(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let mut hash: u64 = 0xcbf29ce484222325;
    for byte in s.bytes() {
        hash ^= byte as u64;
        hash = hash.wrapping_mul(0x100000001b3);
    }
    Ok(PerlValue::integer(hash as i64))
}

/// `djb2 STR` — DJB2 hash.
fn builtin_djb2(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let mut hash: u64 = 5381;
    for byte in s.bytes() {
        hash = hash.wrapping_mul(33).wrapping_add(byte as u64);
    }
    Ok(PerlValue::integer(hash as i64))
}

// ─────────────────────────────────────────────────────────────────────────
// Extended stdlib: Validation
// ─────────────────────────────────────────────────────────────────────────

/// `is_credit_card STR` — validates credit card number (Luhn).
fn builtin_is_credit_card(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let digits: Vec<u32> = s
        .chars()
        .filter(|c| c.is_ascii_digit())
        .map(|c| c.to_digit(10).unwrap())
        .collect();
    if digits.len() < 13 || digits.len() > 19 {
        return Ok(bool_iv(false));
    }
    let mut sum = 0u32;
    let mut double = false;
    for &d in digits.iter().rev() {
        let mut digit = d;
        if double {
            digit *= 2;
            if digit > 9 {
                digit -= 9;
            }
        }
        sum += digit;
        double = !double;
    }
    Ok(bool_iv(sum.is_multiple_of(10)))
}

/// `is_isbn10 STR` — validates ISBN-10.
fn builtin_is_isbn10(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let chars: Vec<char> = s
        .chars()
        .filter(|c| c.is_ascii_digit() || *c == 'X' || *c == 'x')
        .collect();
    if chars.len() != 10 {
        return Ok(bool_iv(false));
    }
    let mut sum = 0i32;
    for (i, c) in chars.iter().enumerate() {
        let val = if *c == 'X' || *c == 'x' {
            10
        } else {
            c.to_digit(10).unwrap() as i32
        };
        sum += val * (10 - i as i32);
    }
    Ok(bool_iv(sum % 11 == 0))
}

/// `is_isbn13 STR` — validates ISBN-13.
fn builtin_is_isbn13(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let digits: Vec<u32> = s
        .chars()
        .filter(|c| c.is_ascii_digit())
        .map(|c| c.to_digit(10).unwrap())
        .collect();
    if digits.len() != 13 {
        return Ok(bool_iv(false));
    }
    let sum: u32 = digits
        .iter()
        .enumerate()
        .map(|(i, &d)| if i % 2 == 0 { d } else { d * 3 })
        .sum();
    Ok(bool_iv(sum.is_multiple_of(10)))
}

/// `is_iban STR` — validates IBAN (basic check).
fn builtin_is_iban(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args)
        .to_string()
        .replace(|c: char| c.is_whitespace(), "")
        .to_uppercase();
    if s.len() < 15 || s.len() > 34 {
        return Ok(bool_iv(false));
    }
    if !s.chars().take(2).all(|c| c.is_ascii_alphabetic()) {
        return Ok(bool_iv(false));
    }
    if !s.chars().skip(2).take(2).all(|c| c.is_ascii_digit()) {
        return Ok(bool_iv(false));
    }
    let rearranged = format!("{}{}", &s[4..], &s[..4]);
    let numeric: String = rearranged
        .chars()
        .map(|c| {
            if c.is_ascii_digit() {
                c.to_string()
            } else {
                ((c as u8) - b'A' + 10).to_string()
            }
        })
        .collect();
    let mut remainder = 0u64;
    for chunk in numeric.as_bytes().chunks(9) {
        let s = std::str::from_utf8(chunk).unwrap_or("0");
        let n: u64 = format!("{}{}", remainder, s).parse().unwrap_or(0);
        remainder = n % 97;
    }
    Ok(bool_iv(remainder == 1))
}

/// `is_hex STR` — validates hexadecimal string.
fn builtin_is_hex_str(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    Ok(bool_iv(
        !s.is_empty() && s.chars().all(|c| c.is_ascii_hexdigit()),
    ))
}

/// `is_binary STR` — validates binary string.
fn builtin_is_binary_str(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    Ok(bool_iv(
        !s.is_empty() && s.chars().all(|c| c == '0' || c == '1'),
    ))
}

/// `is_octal STR` — validates octal string.
fn builtin_is_octal_str(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    Ok(bool_iv(
        !s.is_empty() && s.chars().all(|c| ('0'..='7').contains(&c)),
    ))
}

/// `is_json STR` — validates JSON syntax (basic).
fn builtin_is_json(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    Ok(bool_iv(
        serde_json::from_str::<serde_json::Value>(&s).is_ok(),
    ))
}

/// `is_base64 STR` — validates base64 string.
fn builtin_is_base64(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let s = s.trim();
    if s.is_empty() {
        return Ok(bool_iv(false));
    }
    let valid_chars = s
        .chars()
        .all(|c| c.is_ascii_alphanumeric() || c == '+' || c == '/' || c == '=');
    Ok(bool_iv(valid_chars && s.len().is_multiple_of(4)))
}

/// `is_semver STR` — validates semantic version.
fn builtin_is_semver(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let re = regex::Regex::new(r"^v?(0|[1-9]\d*)\.(0|[1-9]\d*)\.(0|[1-9]\d*)(?:-([\da-zA-Z-]+(?:\.[\da-zA-Z-]+)*))?(?:\+([\da-zA-Z-]+(?:\.[\da-zA-Z-]+)*))?$").unwrap();
    Ok(bool_iv(re.is_match(&s)))
}

/// `is_slug STR` — validates URL slug.
fn builtin_is_slug(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string();
    let re = regex::Regex::new(r"^[a-z0-9]+(?:-[a-z0-9]+)*$").unwrap();
    Ok(bool_iv(re.is_match(&s)))
}

/// `slugify STR` — converts string to URL slug.
fn builtin_slugify(interp: &Interpreter, args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = first_arg_or_topic(interp, args).to_string().to_lowercase();
    let slug: String = s
        .chars()
        .map(|c| if c.is_ascii_alphanumeric() { c } else { '-' })
        .collect::<String>()
        .split('-')
        .filter(|s| !s.is_empty())
        .collect::<Vec<_>>()
        .join("-");
    Ok(PerlValue::string(slug))
}

