/// `entropy` — Shannon entropy.
fn builtin_entropy(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let xs = collect_numbers(args);
    let sum: f64 = xs.iter().sum();
    if sum == 0.0 {
        return Ok(PerlValue::float(0.0));
    }
    let e: f64 = xs
        .iter()
        .filter(|&&x| x > 0.0)
        .map(|&x| {
            let p = x / sum;
            -p * p.ln()
        })
        .sum();
    Ok(PerlValue::float(e))
}
