/// `suffix_sums` — Suffix sums.
fn builtin_suffix_sums(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let xs = collect_numbers(args);
    let n = xs.len();
    let mut sums = vec![0.0; n];
    if n > 0 {
        sums[n - 1] = xs[n - 1];
        for i in (0..n - 1).rev() {
            sums[i] = sums[i + 1] + xs[i];
        }
    }
    Ok(PerlValue::array(
        sums.into_iter().map(PerlValue::float).collect(),
    ))
}
