/// `inc N` — add 1; integer stays integer (matching `Op::Inc` so JIT and
/// interpreter paths agree; the compiler's `Op::Inc` only runs for top-level
/// calls, so without this dispatch `inc` inside a coderef body errors out as
/// an unknown sub).
fn builtin_inc(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let v = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    Ok(if let Some(n) = v.as_integer() {
        PerlValue::integer(n.wrapping_add(1))
    } else {
        PerlValue::float(v.to_number() + 1.0)
    })
}

/// `dec N` — subtract 1; mirrors `Op::Dec`. See [`builtin_inc`] for why.
fn builtin_dec(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let v = args.first().cloned().unwrap_or(PerlValue::UNDEF);
    Ok(if let Some(n) = v.as_integer() {
        PerlValue::integer(n.wrapping_sub(1))
    } else {
        PerlValue::float(v.to_number() - 1.0)
    })
}

/// Split a string into word boundaries for case conversion.
fn split_case_words(s: &str) -> Vec<String> {
    let mut words = Vec::new();
    let mut cur = String::new();
    for c in s.chars() {
        if c == '_' || c == '-' || c == ' ' || c == '\t' {
            if !cur.is_empty() {
                words.push(cur.clone());
                cur.clear();
            }
        } else if c.is_uppercase()
            && !cur.is_empty()
            && cur.chars().last().is_some_and(|p| p.is_lowercase())
        {
            words.push(cur.clone());
            cur.clear();
            cur.push(c);
        } else {
            cur.push(c);
        }
    }
    if !cur.is_empty() {
        words.push(cur);
    }
    words
}

fn to_snake_case(s: &str) -> String {
    split_case_words(s)
        .iter()
        .map(|w| w.to_lowercase())
        .collect::<Vec<_>>()
        .join("_")
}

fn to_camel_case(s: &str) -> String {
    let words = split_case_words(s);
    let mut result = String::new();
    for (i, w) in words.iter().enumerate() {
        if i == 0 {
            result.push_str(&w.to_lowercase());
        } else {
            let mut chars = w.chars();
            if let Some(first) = chars.next() {
                result.extend(first.to_uppercase());
                result.push_str(&chars.as_str().to_lowercase());
            }
        }
    }
    result
}

fn to_kebab_case(s: &str) -> String {
    split_case_words(s)
        .iter()
        .map(|w| w.to_lowercase())
        .collect::<Vec<_>>()
        .join("-")
}

/// `snake_case STRING` — convert to snake_case.
/// `snake_case ITERATOR` — map each element (streaming).
fn builtin_snake_case(args: &[PerlValue]) -> PerlResult<PerlValue> {
    if let Some(v) = args.first() {
        if v.is_iterator() {
            let source = v.clone().into_iterator();
            return Ok(PerlValue::iterator(Arc::new(
                crate::map_stream::MapFnIterator::new(source, |s| to_snake_case(&s)),
            )));
        }
    }
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    Ok(PerlValue::string(to_snake_case(&s)))
}

/// `camel_case STRING` — convert to camelCase (lower first).
/// `camel_case ITERATOR` — map each element (streaming).
fn builtin_camel_case(args: &[PerlValue]) -> PerlResult<PerlValue> {
    if let Some(v) = args.first() {
        if v.is_iterator() {
            let source = v.clone().into_iterator();
            return Ok(PerlValue::iterator(Arc::new(
                crate::map_stream::MapFnIterator::new(source, |s| to_camel_case(&s)),
            )));
        }
    }
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    Ok(PerlValue::string(to_camel_case(&s)))
}

/// `kebab_case STRING` — convert to kebab-case.
/// `kebab_case ITERATOR` — map each element (streaming).
fn builtin_kebab_case(args: &[PerlValue]) -> PerlResult<PerlValue> {
    if let Some(v) = args.first() {
        if v.is_iterator() {
            let source = v.clone().into_iterator();
            return Ok(PerlValue::iterator(Arc::new(
                crate::map_stream::MapFnIterator::new(source, |s| to_kebab_case(&s)),
            )));
        }
    }
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    Ok(PerlValue::string(to_kebab_case(&s)))
}

/// `to_toml VALUE` — serialize a PerlValue to a TOML string.
/// TOML requires a table at root. Anything else gets wrapped:
/// * arrayref of hashrefs → `[[data]]` array-of-tables.
/// * arrayref of arrayrefs / scalars → `data = [...]` top-level array.
/// * single scalar → `value = …`.
///
/// Single hashrefs with single-key entries (the `map +{ k => v }` pattern)
/// are merged into one flat table — otherwise each row produces its own
/// blank-line-separated block, which doesn't round-trip as valid TOML.
fn builtin_to_toml(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let root = normalize_serialize_root(args);
    Ok(PerlValue::string(toml_root(&root)))
}

/// Produce a TOML document from an arbitrary root value, wrapping anything
/// that isn't already a table.
fn toml_root(val: &PerlValue) -> String {
    if val.is_undef() {
        return String::new();
    }
    if val.as_hash_ref().is_some() {
        return perl_value_to_toml_string(val, 0);
    }
    if let Some(ar) = val.as_array_ref() {
        let items = ar.read().clone();
        // AoH of single-key hashes → merge into one flat table.
        // This matches `f |> map +{ $_ => size $_ }` — the idiomatic way to
        // tag each item with a value, and the natural TOML is one table.
        let all_single_key_hash = !items.is_empty()
            && items
                .iter()
                .all(|v| v.as_hash_ref().is_some_and(|hr| hr.read().len() == 1));
        if all_single_key_hash {
            let mut merged: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
            for v in &items {
                if let Some(hr) = v.as_hash_ref() {
                    for (k, inner) in hr.read().iter() {
                        merged.insert(k.clone(), inner.clone());
                    }
                }
            }
            let wrapped = PerlValue::hash_ref(Arc::new(RwLock::new(merged)));
            return perl_value_to_toml_string(&wrapped, 0);
        }
        // AoH with multiple keys → `[[data]]` array of tables.
        let all_hash = !items.is_empty() && items.iter().all(|v| v.as_hash_ref().is_some());
        if all_hash {
            let mut buf = String::new();
            for item in &items {
                if let Some(hr) = item.as_hash_ref() {
                    buf.push_str("[[data]]\n");
                    for (k, v) in hr.read().iter() {
                        buf.push_str(&format!("{} = {}\n", k, toml_scalar(v)));
                    }
                }
            }
            return buf;
        }
        // AoA / mixed / scalars → `data = [...]` top-level array.
        let mut buf = String::from("data = [");
        let parts: Vec<String> = items.iter().map(toml_array_value).collect();
        buf.push_str(&parts.join(", "));
        buf.push_str("]\n");
        return buf;
    }
    // Plain scalar → single-key table.
    format!("value = {}\n", toml_scalar(val))
}

/// TOML-format a single value used inside an inline array — recurses for
/// nested arrays (e.g. AoA becomes `[[...], [...]]`).
fn toml_array_value(val: &PerlValue) -> String {
    if let Some(ar) = val.as_array_ref() {
        let parts: Vec<String> = ar.read().iter().map(toml_array_value).collect();
        format!("[{}]", parts.join(", "))
    } else if let Some(hr) = val.as_hash_ref() {
        // Inline table for a nested hashref inside a regular array.
        let parts: Vec<String> = hr
            .read()
            .iter()
            .map(|(k, v)| format!("{} = {}", k, toml_scalar(v)))
            .collect();
        format!("{{ {} }}", parts.join(", "))
    } else {
        toml_scalar(val)
    }
}

fn perl_value_to_toml_string(val: &PerlValue, _depth: usize) -> String {
    if val.is_undef() {
        return String::new();
    }
    if let Some(hr) = val.as_hash_ref() {
        let guard = hr.read();
        let mut buf = String::new();
        let mut tables = Vec::new();
        // First pass: simple key-value pairs
        for (k, v) in guard.iter() {
            if v.as_hash_ref().is_some() {
                tables.push((k.clone(), v.clone()));
            } else if let Some(ar) = v.as_array_ref() {
                let arr_guard = ar.read();
                // Check if array of tables
                if arr_guard.first().and_then(|v| v.as_hash_ref()).is_some() {
                    tables.push((k.clone(), v.clone()));
                } else {
                    buf.push_str(&format!(
                        "{} = [{}]\n",
                        k,
                        arr_guard
                            .iter()
                            .map(toml_scalar)
                            .collect::<Vec<_>>()
                            .join(", ")
                    ));
                }
            } else {
                buf.push_str(&format!("{} = {}\n", k, toml_scalar(v)));
            }
        }
        // Second pass: nested tables
        for (k, v) in &tables {
            if let Some(hr2) = v.as_hash_ref() {
                buf.push_str(&format!("\n[{}]\n", k));
                let g2 = hr2.read();
                for (k2, v2) in g2.iter() {
                    buf.push_str(&format!("{} = {}\n", k2, toml_scalar(v2)));
                }
            } else if let Some(ar) = v.as_array_ref() {
                let arr_guard = ar.read();
                for item in arr_guard.iter() {
                    buf.push_str(&format!("\n[[{}]]\n", k));
                    if let Some(ihr) = item.as_hash_ref() {
                        let ig = ihr.read();
                        for (ik, iv) in ig.iter() {
                            buf.push_str(&format!("{} = {}\n", ik, toml_scalar(iv)));
                        }
                    }
                }
            }
        }
        buf
    } else {
        toml_scalar(val)
    }
}

fn toml_scalar(val: &PerlValue) -> String {
    if val.is_undef() {
        return "\"\"".to_string();
    }
    if val.is_integer_like() {
        return format!("{}", val.to_int());
    }
    if val.is_float_like() {
        return format!("{}", val.to_number());
    }
    let s = val.to_string();
    if s == "true" || s == "false" {
        return s;
    }
    format!(
        "\"{}\"",
        s.replace('\\', "\\\\")
            .replace('"', "\\\"")
            .replace('\n', "\\n")
    )
}

/// `to_yaml VALUE` — serialize a PerlValue to a YAML string.
/// Always emits a single document (no `---` per-arg split when called via
/// pipeline spread — those are logically one value, not N documents).
fn builtin_to_yaml(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let val = normalize_serialize_root(args);
    let mut buf = String::from("---\n");
    yaml_value(&mut buf, &val, 0);
    Ok(PerlValue::string(buf))
}

fn yaml_value(buf: &mut String, val: &PerlValue, depth: usize) {
    let indent = "  ".repeat(depth);
    if val.is_undef() {
        buf.push_str("~\n");
        return;
    }
    if let Some(hr) = val.as_hash_ref() {
        let guard = hr.read();
        if guard.is_empty() {
            buf.push_str("{}\n");
            return;
        }
        if depth > 0 {
            buf.push('\n');
        }
        for (k, v) in guard.iter() {
            buf.push_str(&format!("{}{}:", indent, k));
            if v.as_hash_ref().is_some() || v.as_array_ref().is_some() {
                yaml_value(buf, v, depth + 1);
            } else {
                buf.push(' ');
                yaml_value(buf, v, depth + 1);
            }
        }
        return;
    }
    if let Some(ar) = val.as_array_ref() {
        let guard = ar.read();
        if guard.is_empty() {
            buf.push_str("[]\n");
            return;
        }
        if depth > 0 {
            buf.push('\n');
        }
        for item in guard.iter() {
            buf.push_str(&format!("{}- ", indent));
            if item.as_hash_ref().is_some() || item.as_array_ref().is_some() {
                // Inline the first level for array-of-hashes
                if let Some(ihr) = item.as_hash_ref() {
                    let ig = ihr.read();
                    let mut first = true;
                    for (ik, iv) in ig.iter() {
                        if first {
                            buf.push_str(&format!("{}: ", ik));
                            yaml_scalar(buf, iv);
                            first = false;
                        } else {
                            buf.push_str(&format!("{}  {}: ", indent, ik));
                            yaml_scalar(buf, iv);
                        }
                    }
                } else {
                    yaml_value(buf, item, depth + 1);
                }
            } else {
                yaml_scalar(buf, item);
            }
        }
        return;
    }
    yaml_scalar(buf, val);
}

fn yaml_scalar(buf: &mut String, val: &PerlValue) {
    if val.is_undef() {
        buf.push_str("~\n");
    } else if val.is_integer_like() {
        buf.push_str(&format!("{}\n", val.to_int()));
    } else if val.is_float_like() {
        buf.push_str(&format!("{}\n", val.to_number()));
    } else {
        let s = val.to_string();
        if s.contains(':')
            || s.contains('#')
            || s.contains('\n')
            || s.contains('"')
            || s.is_empty()
            || s == "true"
            || s == "false"
            || s == "null"
        {
            buf.push_str(&format!(
                "\"{}\"\n",
                s.replace('\\', "\\\\").replace('"', "\\\"")
            ));
        } else {
            buf.push_str(&format!("{}\n", s));
        }
    }
}

/// `to_xml VALUE` — serialize a PerlValue to an XML string.
/// Arbitrary hash keys are allowed — when a key isn't a valid XML `Name`
/// (e.g. starts with `.` or contains `/`), the entry is emitted as
/// `<entry key="…">value</entry>` instead of `<key>value</key>`, which
/// would produce malformed XML.
fn builtin_to_xml(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let val = normalize_serialize_root(args);
    let mut buf = String::from("<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n");
    xml_value(&mut buf, "root", &val, 0);
    Ok(PerlValue::string(buf))
}

fn xml_value(buf: &mut String, tag: &str, val: &PerlValue, depth: usize) {
    let indent = "  ".repeat(depth);
    if val.is_undef() {
        buf.push_str(&format!("{}<{}/>\n", indent, tag));
        return;
    }
    if let Some(hr) = val.as_hash_ref() {
        let guard = hr.read();
        buf.push_str(&format!("{}<{}>\n", indent, tag));
        for (k, v) in guard.iter() {
            xml_entry(buf, k, v, depth + 1);
        }
        buf.push_str(&format!("{}</{}>\n", indent, tag));
        return;
    }
    if let Some(ar) = val.as_array_ref() {
        let guard = ar.read();
        buf.push_str(&format!("{}<{}>\n", indent, tag));
        for item in guard.iter() {
            xml_value(buf, "item", item, depth + 1);
        }
        buf.push_str(&format!("{}</{}>\n", indent, tag));
        return;
    }
    let s = xml_escape(&val.to_string());
    buf.push_str(&format!("{}<{}>{}</{}>\n", indent, tag, s, tag));
}

/// Emit one hash entry. If `key` is a valid XML `Name`, use it as the tag;
/// otherwise fall back to `<entry key="…">…</entry>` so the output stays
/// well-formed for arbitrary keys (file paths, URLs, etc.).
fn xml_entry(buf: &mut String, key: &str, val: &PerlValue, depth: usize) {
    if is_valid_xml_name(key) {
        xml_value(buf, key, val, depth);
        return;
    }
    let indent = "  ".repeat(depth);
    let attr = xml_escape(key);
    if val.is_undef() {
        buf.push_str(&format!("{}<entry key=\"{}\"/>\n", indent, attr));
        return;
    }
    if val.as_hash_ref().is_some() || val.as_array_ref().is_some() {
        // Complex child → open/close tags, recurse with a neutral inner tag.
        buf.push_str(&format!("{}<entry key=\"{}\">\n", indent, attr));
        // Recurse without re-wrapping in another <root>: walk children directly.
        if let Some(hr) = val.as_hash_ref() {
            for (k, v) in hr.read().iter() {
                xml_entry(buf, k, v, depth + 1);
            }
        } else if let Some(ar) = val.as_array_ref() {
            for item in ar.read().iter() {
                xml_value(buf, "item", item, depth + 1);
            }
        }
        buf.push_str(&format!("{}</entry>\n", indent));
        return;
    }
    let s = xml_escape(&val.to_string());
    buf.push_str(&format!(
        "{}<entry key=\"{}\">{}</entry>\n",
        indent, attr, s
    ));
}

/// XML 1.0 `Name` production (simplified ASCII subset — colon is intentionally
/// excluded since we don't resolve namespaces). Rejects empty, non-alpha starts,
/// and any char outside `[A-Za-z0-9_.-]` after the first.
fn is_valid_xml_name(s: &str) -> bool {
    let mut chars = s.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    if !(first.is_ascii_alphabetic() || first == '_') {
        return false;
    }
    chars.all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '-' || c == '.')
}

fn xml_escape(s: &str) -> String {
    s.replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
        .replace('\'', "&apos;")
}

// ── from_json ───────────────────────────────────────────────────────────

/// `from_json STRING` — parse a JSON string into a PerlValue.
fn builtin_from_json(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    parse_json_value(&s)
}

fn parse_json_value(s: &str) -> PerlResult<PerlValue> {
    let s = s.trim();
    if s.is_empty() || s == "null" {
        return Ok(PerlValue::UNDEF);
    }
    if s == "true" {
        return Ok(PerlValue::integer(1));
    }
    if s == "false" {
        return Ok(PerlValue::integer(0));
    }
    if s.starts_with('"') && s.ends_with('"') {
        let inner = &s[1..s.len() - 1];
        return Ok(PerlValue::string(
            inner
                .replace("\\n", "\n")
                .replace("\\t", "\t")
                .replace("\\r", "\r")
                .replace("\\\"", "\"")
                .replace("\\\\", "\\"),
        ));
    }
    if let Ok(n) = s.parse::<i64>() {
        return Ok(PerlValue::integer(n));
    }
    if let Ok(f) = s.parse::<f64>() {
        return Ok(PerlValue::float(f));
    }
    if s.starts_with('[') && s.ends_with(']') {
        return parse_json_array(s);
    }
    if s.starts_with('{') && s.ends_with('}') {
        return parse_json_object(s);
    }
    Ok(PerlValue::string(s.into()))
}

fn parse_json_array(s: &str) -> PerlResult<PerlValue> {
    let inner = &s[1..s.len() - 1];
    if inner.trim().is_empty() {
        return Ok(PerlValue::array_ref(Arc::new(RwLock::new(Vec::new()))));
    }
    let mut items = Vec::new();
    let mut depth = 0;
    let mut in_string = false;
    let mut escape = false;
    let mut start = 0;
    for (i, c) in inner.char_indices() {
        if escape {
            escape = false;
            continue;
        }
        match c {
            '\\' if in_string => escape = true,
            '"' => in_string = !in_string,
            '[' | '{' if !in_string => depth += 1,
            ']' | '}' if !in_string => depth -= 1,
            ',' if !in_string && depth == 0 => {
                items.push(parse_json_value(inner[start..i].trim())?);
                start = i + 1;
            }
            _ => {}
        }
    }
    if start < inner.len() {
        let remaining = inner[start..].trim();
        if !remaining.is_empty() {
            items.push(parse_json_value(remaining)?);
        }
    }
    Ok(PerlValue::array_ref(Arc::new(RwLock::new(items))))
}

fn parse_json_object(s: &str) -> PerlResult<PerlValue> {
    let inner = &s[1..s.len() - 1];
    if inner.trim().is_empty() {
        return Ok(PerlValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    let hash: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    let hash = Arc::new(RwLock::new(hash));
    let mut depth = 0;
    let mut in_string = false;
    let mut escape = false;
    let mut start = 0;
    for (i, c) in inner.char_indices() {
        if escape {
            escape = false;
            continue;
        }
        match c {
            '\\' if in_string => escape = true,
            '"' => in_string = !in_string,
            '[' | '{' if !in_string => depth += 1,
            ']' | '}' if !in_string => depth -= 1,
            ',' if !in_string && depth == 0 => {
                parse_json_kv(&inner[start..i], &hash)?;
                start = i + 1;
            }
            _ => {}
        }
    }
    if start < inner.len() {
        let remaining = inner[start..].trim();
        if !remaining.is_empty() {
            parse_json_kv(remaining, &hash)?;
        }
    }
    Ok(PerlValue::hash_ref(hash))
}

fn parse_json_kv(
    kv: &str,
    hash: &Arc<RwLock<indexmap::IndexMap<String, PerlValue>>>,
) -> PerlResult<()> {
    let kv = kv.trim();
    let colon = kv
        .find(':')
        .ok_or_else(|| PerlError::runtime("Invalid JSON: missing colon", 0))?;
    let key = kv[..colon].trim();
    let key = if key.starts_with('"') && key.ends_with('"') {
        &key[1..key.len() - 1]
    } else {
        key
    };
    let val_str = kv[colon + 1..].trim();
    let val = parse_json_value(val_str)?;
    hash.write().insert(key.to_string(), val);
    Ok(())
}

// ── from_yaml ───────────────────────────────────────────────────────────

/// `from_yaml STRING` — parse a YAML string into a PerlValue.
fn builtin_from_yaml(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    parse_yaml(&s)
}

fn parse_yaml(s: &str) -> PerlResult<PerlValue> {
    let s = s.trim();
    if s.is_empty() || s == "~" || s == "null" {
        return Ok(PerlValue::UNDEF);
    }
    let s = s
        .strip_prefix("---")
        .map(|rest| rest.trim_start())
        .unwrap_or(s);
    if s.is_empty() || s == "~" || s == "null" {
        return Ok(PerlValue::UNDEF);
    }
    if s == "true" {
        return Ok(PerlValue::integer(1));
    }
    if s == "false" {
        return Ok(PerlValue::integer(0));
    }
    if s == "{}" {
        return Ok(PerlValue::hash_ref(Arc::new(RwLock::new(
            indexmap::IndexMap::new(),
        ))));
    }
    if s == "[]" {
        return Ok(PerlValue::array_ref(Arc::new(RwLock::new(Vec::new()))));
    }
    if let Ok(n) = s.parse::<i64>() {
        return Ok(PerlValue::integer(n));
    }
    if let Ok(f) = s.parse::<f64>() {
        return Ok(PerlValue::float(f));
    }
    if (s.starts_with('"') && s.ends_with('"')) || (s.starts_with('\'') && s.ends_with('\'')) {
        let inner = &s[1..s.len() - 1];
        return Ok(PerlValue::string(
            inner.replace("\\n", "\n").replace("\\\"", "\""),
        ));
    }
    if s.starts_with("- ") || s.starts_with("-\n") {
        return parse_yaml_array(s);
    }
    if s.contains(':') && !s.starts_with('"') {
        return parse_yaml_hash(s);
    }
    Ok(PerlValue::string(s.into()))
}

fn parse_yaml_array(s: &str) -> PerlResult<PerlValue> {
    let mut items = Vec::new();
    let mut current = String::new();
    let mut in_item = false;
    for line in s.lines() {
        let trimmed = line.trim_start();
        if let Some(stripped) = trimmed.strip_prefix("- ") {
            if in_item && !current.is_empty() {
                items.push(parse_yaml(&current)?);
            }
            current = stripped.to_string();
            in_item = true;
        } else if in_item {
            current.push('\n');
            current.push_str(line);
        }
    }
    if in_item && !current.is_empty() {
        items.push(parse_yaml(&current)?);
    }
    Ok(PerlValue::array_ref(Arc::new(RwLock::new(items))))
}

fn parse_yaml_hash(s: &str) -> PerlResult<PerlValue> {
    let hash: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    let hash = Arc::new(RwLock::new(hash));
    let mut current_key: Option<String> = None;
    let mut current_value = String::new();
    let mut base_indent: Option<usize> = None;
    for line in s.lines() {
        let indent = line.len() - line.trim_start().len();
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        if base_indent.is_none() {
            base_indent = Some(indent);
        }
        if indent == base_indent.unwrap_or(0) {
            if let Some(key) = current_key.take() {
                let val = parse_yaml(&current_value)?;
                hash.write().insert(key, val);
                current_value.clear();
            }
            if let Some(colon_pos) = trimmed.find(':') {
                let key = trimmed[..colon_pos].trim();
                let rest = trimmed[colon_pos + 1..].trim();
                current_key = Some(key.to_string());
                if !rest.is_empty() {
                    current_value = rest.to_string();
                }
            }
        } else if current_key.is_some() {
            if !current_value.is_empty() {
                current_value.push('\n');
            }
            current_value.push_str(trimmed);
        }
    }
    if let Some(key) = current_key {
        let val = parse_yaml(&current_value)?;
        hash.write().insert(key, val);
    }
    Ok(PerlValue::hash_ref(hash))
}

// ── from_toml ───────────────────────────────────────────────────────────

/// `from_toml STRING` — parse a TOML string into a PerlValue.
fn builtin_from_toml(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    parse_toml(&s)
}

fn parse_toml(s: &str) -> PerlResult<PerlValue> {
    let hash: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    let hash = Arc::new(RwLock::new(hash));
    let mut current_section: Option<String> = None;
    for line in s.lines() {
        let trimmed = line.trim();
        if trimmed.is_empty() || trimmed.starts_with('#') {
            continue;
        }
        if trimmed.starts_with('[') && trimmed.ends_with(']') {
            current_section = Some(trimmed[1..trimmed.len() - 1].to_string());
            continue;
        }
        if let Some(eq_pos) = trimmed.find('=') {
            let key = trimmed[..eq_pos].trim();
            let val_str = trimmed[eq_pos + 1..].trim();
            let val = parse_toml_value(val_str);
            if let Some(ref section) = current_section {
                let section_hash = {
                    let guard = hash.read();
                    guard.get(section).and_then(|v| v.as_hash_ref())
                };
                let section_hash = section_hash.unwrap_or_else(|| {
                    let new_hash: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
                    let new_hash = Arc::new(RwLock::new(new_hash));
                    hash.write()
                        .insert(section.clone(), PerlValue::hash_ref(new_hash.clone()));
                    new_hash
                });
                section_hash.write().insert(key.to_string(), val);
            } else {
                hash.write().insert(key.to_string(), val);
            }
        }
    }
    Ok(PerlValue::hash_ref(hash))
}

fn parse_toml_value(s: &str) -> PerlValue {
    let s = s.trim();
    if s == "true" {
        return PerlValue::integer(1);
    }
    if s == "false" {
        return PerlValue::integer(0);
    }
    if (s.starts_with('"') && s.ends_with('"')) || (s.starts_with('\'') && s.ends_with('\'')) {
        let inner = &s[1..s.len() - 1];
        return PerlValue::string(inner.replace("\\n", "\n").replace("\\\"", "\""));
    }
    if s.starts_with('[') && s.ends_with(']') {
        let inner = &s[1..s.len() - 1];
        let items: Vec<PerlValue> = inner
            .split(',')
            .map(|item| parse_toml_value(item.trim()))
            .collect();
        return PerlValue::array_ref(Arc::new(RwLock::new(items)));
    }
    if let Ok(n) = s.parse::<i64>() {
        return PerlValue::integer(n);
    }
    if let Ok(f) = s.parse::<f64>() {
        return PerlValue::float(f);
    }
    PerlValue::string(s.into())
}

// ── from_xml ────────────────────────────────────────────────────────────

/// `from_xml STRING` — parse an XML string into a PerlValue.
fn builtin_from_xml(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    parse_xml(&s)
}

fn parse_xml(s: &str) -> PerlResult<PerlValue> {
    let s = s.trim();
    let s = if s.starts_with("<?xml") {
        s.find("?>").map(|i| &s[i + 2..]).unwrap_or(s).trim()
    } else {
        s
    };
    if s.is_empty() {
        return Ok(PerlValue::UNDEF);
    }
    parse_xml_element(s).map(|(val, _)| val)
}

fn find_matching_close_tag(s: &str, open_tag: &str, close_tag: &str) -> Option<usize> {
    let mut depth = 1;
    let mut pos = 0;
    while pos < s.len() {
        if let Some(close_offset) = s[pos..].find(close_tag) {
            let close_abs = pos + close_offset;
            let mut open_search_end = close_abs;
            while let Some(open_offset) = s[pos..open_search_end].find(open_tag) {
                let open_abs = pos + open_offset;
                let after_open = &s[open_abs + open_tag.len()..];
                let next_char = after_open.chars().next();
                if next_char == Some('>') || next_char == Some(' ') || next_char == Some('/') {
                    depth += 1;
                }
                pos = open_abs + 1;
                open_search_end = close_abs;
            }
            depth -= 1;
            if depth == 0 {
                return Some(close_abs);
            }
            pos = close_abs + close_tag.len();
        } else {
            return None;
        }
    }
    None
}

fn parse_xml_element(s: &str) -> PerlResult<(PerlValue, &str)> {
    let s = s.trim_start();
    if !s.starts_with('<') {
        let end = s.find('<').unwrap_or(s.len());
        let text = xml_unescape(s[..end].trim());
        return Ok((PerlValue::string(text), &s[end..]));
    }
    let tag_end = s
        .find('>')
        .ok_or_else(|| PerlError::runtime("Invalid XML: unclosed tag", 0))?;
    let tag_content = &s[1..tag_end];
    if let Some(stripped) = tag_content.strip_suffix('/') {
        let tag_name = stripped.split_whitespace().next().unwrap_or("");
        let hash: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
        let hash = Arc::new(RwLock::new(hash));
        hash.write().insert(tag_name.to_string(), PerlValue::UNDEF);
        return Ok((PerlValue::hash_ref(hash), &s[tag_end + 1..]));
    }
    let tag_name = tag_content.split_whitespace().next().unwrap_or("");
    let open_tag = format!("<{}", tag_name);
    let close_tag = format!("</{}>", tag_name);
    let content_start = tag_end + 1;
    let close_pos = find_matching_close_tag(&s[content_start..], &open_tag, &close_tag)
        .ok_or_else(|| PerlError::runtime(format!("Invalid XML: unclosed tag {}", tag_name), 0))?;
    let content = &s[content_start..content_start + close_pos];
    let rest = &s[content_start + close_pos + close_tag.len()..];
    let content = content.trim();
    if content.is_empty() {
        let hash: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
        let hash = Arc::new(RwLock::new(hash));
        hash.write()
            .insert(tag_name.to_string(), PerlValue::string("".into()));
        return Ok((PerlValue::hash_ref(hash), rest));
    }
    if !content.contains('<') {
        let hash: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
        let hash = Arc::new(RwLock::new(hash));
        hash.write().insert(
            tag_name.to_string(),
            PerlValue::string(xml_unescape(content)),
        );
        return Ok((PerlValue::hash_ref(hash), rest));
    }
    let inner_hash: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    let inner_hash = Arc::new(RwLock::new(inner_hash));
    let mut remaining = content;
    while !remaining.trim().is_empty() {
        let (child, new_remaining) = parse_xml_element(remaining)?;
        if let Some(hr) = child.as_hash_ref() {
            for (k, v) in hr.read().iter() {
                inner_hash.write().insert(k.clone(), v.clone());
            }
        }
        remaining = new_remaining;
    }
    let hash: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
    let hash = Arc::new(RwLock::new(hash));
    hash.write()
        .insert(tag_name.to_string(), PerlValue::hash_ref(inner_hash));
    Ok((PerlValue::hash_ref(hash), rest))
}

fn xml_unescape(s: &str) -> String {
    s.replace("&amp;", "&")
        .replace("&lt;", "<")
        .replace("&gt;", ">")
        .replace("&quot;", "\"")
        .replace("&apos;", "'")
}

// ── from_csv ────────────────────────────────────────────────────────────

/// `from_csv STRING` — parse a CSV string into an array of hashes.
/// First line is treated as headers.
fn builtin_from_csv(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let s = args.first().map(|v| v.to_string()).unwrap_or_default();
    parse_csv(&s)
}

fn parse_csv(s: &str) -> PerlResult<PerlValue> {
    let mut lines = s.lines();
    let header_line = match lines.next() {
        Some(h) => h,
        None => return Ok(PerlValue::array_ref(Arc::new(RwLock::new(Vec::new())))),
    };
    let headers: Vec<&str> = parse_csv_line(header_line);
    let mut rows = Vec::new();
    for line in lines {
        if line.trim().is_empty() {
            continue;
        }
        let values = parse_csv_line(line);
        let row: indexmap::IndexMap<String, PerlValue> = indexmap::IndexMap::new();
        let row = Arc::new(RwLock::new(row));
        for (i, header) in headers.iter().enumerate() {
            let val = values
                .get(i)
                .map(|s| PerlValue::string((*s).into()))
                .unwrap_or(PerlValue::UNDEF);
            row.write().insert(header.to_string(), val);
        }
        rows.push(PerlValue::hash_ref(row));
    }
    Ok(PerlValue::array_ref(Arc::new(RwLock::new(rows))))
}

fn parse_csv_line(line: &str) -> Vec<&str> {
    let mut fields = Vec::new();
    let mut start = 0;
    let mut in_quotes = false;
    let bytes = line.as_bytes();
    for (i, &b) in bytes.iter().enumerate() {
        if b == b'"' {
            in_quotes = !in_quotes;
        } else if b == b',' && !in_quotes {
            let field = &line[start..i];
            fields.push(field.trim().trim_matches('"'));
            start = i + 1;
        }
    }
    let field = &line[start..];
    fields.push(field.trim().trim_matches('"'));
    fields
}

// ── to_html ─────────────────────────────────────────────────────────────

/// `to_html VALUE` — serialize a PerlValue to a styled HTML document.
/// Output is a self-contained cyberpunk-themed page (dark bg, neon accents,
/// monospace font) suitable for piping to a file and opening in a browser.
fn builtin_to_html(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let val = normalize_serialize_root(args);
    let mut buf = String::with_capacity(2048);
    buf.push_str(
        "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n\
         <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n\
         <title>stryke — to_html</title>\n<style>\n\
         *{margin:0;padding:0;box-sizing:border-box}\n\
         :root{--bg:#05050a;--bg2:#0a0a14;--card:#0d0d1a;--cyan:#05d9e8;\
         --accent:#ff2a6d;--accent-lt:#ff6b9d;--text:#e0f0ff;--dim:#7a8ba8;\
         --border:#1a1a3e;--green:#39ff14}\n\
         body{font-family:'Share Tech Mono','SF Mono','Fira Code',monospace;\
         background:var(--bg);color:var(--text);line-height:1.55;\
         padding:2rem 1.25rem}\n\
         .wrap{max-width:68rem;margin:0 auto}\n\
         h1{font-family:'Orbitron',sans-serif;font-size:14px;font-weight:900;\
         letter-spacing:3px;text-transform:uppercase;color:var(--cyan);\
         margin:0 0 1rem;padding-bottom:10px;border-bottom:1px solid var(--border)}\n\
         table{border-collapse:collapse;width:100%;margin:0.6rem 0}\n\
         th{background:var(--bg2);color:var(--cyan);font-family:'Orbitron',sans-serif;\
         font-size:10px;font-weight:700;letter-spacing:1px;text-transform:uppercase;\
         text-align:left;padding:6px 10px;border:1px solid var(--border)}\n\
         td{padding:6px 10px;border:1px solid var(--border);color:var(--dim);\
         vertical-align:top;font-size:12px}\n\
         tr:hover td{background:rgba(5,217,232,0.06)}\n\
         .scalar{padding:1rem;border-left:2px solid var(--cyan);background:var(--card);\
         font-size:13px;color:var(--text);white-space:pre-wrap;word-break:break-word}\n\
         .null{color:var(--accent-lt);font-style:italic}\n\
         ul{list-style:none;padding:0}\n\
         ul li{padding:4px 10px;border-bottom:1px solid var(--border);font-size:12px;\
         color:var(--dim)}\n\
         ul li:hover{background:rgba(5,217,232,0.06)}\n\
         ul li::before{content:'▸ ';color:var(--cyan)}\n\
         .nested{margin:0.4rem 0 0.4rem 1rem;border-left:2px solid var(--border);\
         padding-left:0.8rem}\n\
         </style>\n</head>\n<body>\n<div class=\"wrap\">\n\
         <h1>// STRYKE DATA</h1>\n",
    );
    html_value(&mut buf, &val, 0);
    buf.push_str("</div>\n</body>\n</html>\n");
    Ok(PerlValue::string(buf))
}

fn html_value(buf: &mut String, val: &PerlValue, depth: usize) {
    if val.is_undef() {
        buf.push_str("<span class=\"null\">undef</span>\n");
        return;
    }
    if let Some(hr) = val.as_hash_ref() {
        let guard = hr.read();
        if guard.is_empty() {
            buf.push_str("<span class=\"null\">{}</span>\n");
            return;
        }
        // Array-of-hashes at top level → full table
        buf.push_str("<table>\n<thead><tr>");
        for k in guard.keys() {
            buf.push_str("<th>");
            html_escape_into(buf, k);
            buf.push_str("</th>");
        }
        buf.push_str("</tr></thead>\n<tbody><tr>");
        for v in guard.values() {
            buf.push_str("<td>");
            html_cell(buf, v, depth + 1);
            buf.push_str("</td>");
        }
        buf.push_str("</tr></tbody>\n</table>\n");
        return;
    }
    if let Some(ar) = val.as_array_ref() {
        let guard = ar.read();
        if guard.is_empty() {
            buf.push_str("<span class=\"null\">[]</span>\n");
            return;
        }
        // Check if AoH → render as a full table
        if guard.iter().all(|v| v.as_hash_ref().is_some()) {
            // Collect union of keys preserving first-seen order
            let mut headers: Vec<String> = Vec::new();
            let mut seen = std::collections::HashSet::new();
            for row in guard.iter() {
                if let Some(rh) = row.as_hash_ref() {
                    for k in rh.read().keys() {
                        if seen.insert(k.clone()) {
                            headers.push(k.clone());
                        }
                    }
                }
            }
            buf.push_str("<table>\n<thead><tr>");
            for h in &headers {
                buf.push_str("<th>");
                html_escape_into(buf, h);
                buf.push_str("</th>");
            }
            buf.push_str("</tr></thead>\n<tbody>\n");
            for row in guard.iter() {
                buf.push_str("<tr>");
                if let Some(rh) = row.as_hash_ref() {
                    let rg = rh.read();
                    for h in &headers {
                        buf.push_str("<td>");
                        if let Some(v) = rg.get(h) {
                            html_cell(buf, v, depth + 1);
                        }
                        buf.push_str("</td>");
                    }
                }
                buf.push_str("</tr>\n");
            }
            buf.push_str("</tbody>\n</table>\n");
            return;
        }
        // Plain array → unordered list
        buf.push_str("<ul>\n");
        for item in guard.iter() {
            buf.push_str("<li>");
            html_cell(buf, item, depth + 1);
            buf.push_str("</li>\n");
        }
        buf.push_str("</ul>\n");
        return;
    }
    // Scalar
    buf.push_str("<div class=\"scalar\">");
    html_escape_into(buf, &val.to_string());
    buf.push_str("</div>\n");
}

fn html_cell(buf: &mut String, val: &PerlValue, depth: usize) {
    if val.is_undef() {
        buf.push_str("<span class=\"null\">undef</span>");
        return;
    }
    if val.as_hash_ref().is_some() || val.as_array_ref().is_some() {
        buf.push_str("<div class=\"nested\">");
        html_value(buf, val, depth);
        buf.push_str("</div>");
        return;
    }
    html_escape_into(buf, &val.to_string());
}

fn html_escape_into(buf: &mut String, s: &str) {
    for c in s.chars() {
        match c {
            '&' => buf.push_str("&amp;"),
            '<' => buf.push_str("&lt;"),
            '>' => buf.push_str("&gt;"),
            '"' => buf.push_str("&quot;"),
            '\'' => buf.push_str("&#39;"),
            _ => buf.push(c),
        }
    }
}

// ── to_markdown ─────────────────────────────────────────────────────────

/// `to_markdown VALUE` — serialize a PerlValue to a Markdown string.
/// Hashes render as tables, arrays as bullet lists, AoH as full tables,
/// and scalars as plain text.
fn builtin_to_markdown(args: &[PerlValue]) -> PerlResult<PerlValue> {
    let val = normalize_serialize_root(args);
    let mut buf = String::with_capacity(512);
    md_value(&mut buf, &val, 0);
    Ok(PerlValue::string(buf))
}

fn md_value(buf: &mut String, val: &PerlValue, depth: usize) {
    if val.is_undef() {
        buf.push_str("*undef*\n");
        return;
    }
    if let Some(hr) = val.as_hash_ref() {
        let guard = hr.read();
        if guard.is_empty() {
            buf.push_str("*{}*\n");
            return;
        }
        // Single hash → 2-column table
        buf.push_str("| Key | Value |\n| --- | --- |\n");
        for (k, v) in guard.iter() {
            buf.push_str("| ");
            md_escape_into(buf, k);
            buf.push_str(" | ");
            md_cell(buf, v);
            buf.push_str(" |\n");
        }
        return;
    }
    if let Some(ar) = val.as_array_ref() {
        let guard = ar.read();
        if guard.is_empty() {
            buf.push_str("*[]*\n");
            return;
        }
        // AoH → full table
        if guard.iter().all(|v| v.as_hash_ref().is_some()) {
            let mut headers: Vec<String> = Vec::new();
            let mut seen = std::collections::HashSet::new();
            for row in guard.iter() {
                if let Some(rh) = row.as_hash_ref() {
                    for k in rh.read().keys() {
                        if seen.insert(k.clone()) {
                            headers.push(k.clone());
                        }
                    }
                }
            }
            buf.push_str("| ");
            for (i, h) in headers.iter().enumerate() {
                if i > 0 {
                    buf.push_str(" | ");
                }
                md_escape_into(buf, h);
            }
            buf.push_str(" |\n| ");
            for i in 0..headers.len() {
                if i > 0 {
                    buf.push_str(" | ");
                }
                buf.push_str("---");
            }
            buf.push_str(" |\n");
            for row in guard.iter() {
                buf.push_str("| ");
                if let Some(rh) = row.as_hash_ref() {
                    let rg = rh.read();
                    for (i, h) in headers.iter().enumerate() {
                        if i > 0 {
                            buf.push_str(" | ");
                        }
                        if let Some(v) = rg.get(h) {
                            md_cell(buf, v);
                        }
                    }
                }
                buf.push_str(" |\n");
            }
            return;
        }
        // Plain array → bullet list
        let prefix = "  ".repeat(depth);
        for item in guard.iter() {
            buf.push_str(&prefix);
            buf.push_str("- ");
            if item.as_hash_ref().is_some() || item.as_array_ref().is_some() {
                buf.push('\n');
                md_value(buf, item, depth + 1);
            } else {
                md_cell(buf, item);
                buf.push('\n');
            }
        }
        return;
    }
    // Scalar
    buf.push_str(&val.to_string());
    buf.push('\n');
}

fn md_cell(buf: &mut String, val: &PerlValue) {
    if val.is_undef() {
        buf.push_str("*undef*");
        return;
    }
    if val.is_integer_like() {
        buf.push_str(&val.to_int().to_string());
        return;
    }
    if val.is_float_like() {
        buf.push_str(&val.to_number().to_string());
        return;
    }
    md_escape_into(buf, &val.to_string());
}

fn md_escape_into(buf: &mut String, s: &str) {
    for c in s.chars() {
        match c {
            '|' | '\\' | '*' | '_' | '`' | '[' | ']' | '#' => {
                buf.push('\\');
                buf.push(c);
            }
            _ => buf.push(c),
        }
    }
}

/// `to_pdf CONTENT [, PATH]` — generate PDF from text, SVG, or data.
/// If PATH given, writes to file and returns path. Otherwise returns raw PDF bytes as string.
/// Detects input type:
///   - SVG string → embeds SVG in PDF page
///   - Plain text / multiline → renders as monospace text pages
///   - Array of strings → one line per element
///   - Hashref → key-value table
///   - Array of hashrefs → tabular data
fn builtin_to_pdf(interp: &Interpreter, args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let content = first_arg_or_topic(interp, args);
    let path = args.get(1).map(|v| v.to_string());

    let s = content.to_string();
    let is_svg = s.trim_start().starts_with("<svg") || s.trim_start().starts_with("<?xml");

    let pdf_bytes = if is_svg {
        svg_to_pdf(&s, line)?
    } else {
        let lines = pdf_content_to_lines(&content);
        generate_pdf(&lines)
    };

    if let Some(p) = path {
        std::fs::write(&p, &pdf_bytes)
            .map_err(|e| PerlError::runtime(format!("to_pdf: {}: {}", p, e), line))?;
        Ok(PerlValue::string(p))
    } else {
        // Write to temp file and return path (raw bytes aren't useful in a pipeline)
        let mut tmp = std::env::temp_dir();
        tmp.push(format!("stryke_{}.pdf", std::process::id()));
        std::fs::write(&tmp, &pdf_bytes)
            .map_err(|e| PerlError::runtime(format!("to_pdf: {}", e), line))?;
        Ok(PerlValue::string(tmp.to_string_lossy().to_string()))
    }
}

/// Convert SVG string to PDF bytes using usvg + svg2pdf.
/// `pdf_text FILE` — extract all text from a PDF file.
/// `html_parse HTML_STRING` — parse HTML and return a document value that can be queried with css_select.
/// If called with one arg, returns the parsed document as a nested hashref tree.
fn builtin_html_parse(
    interp: &Interpreter,
    args: &[PerlValue],
    _line: usize,
) -> PerlResult<PerlValue> {
    let html_str = first_arg_or_topic(interp, args).to_string();
    let doc = scraper::Html::parse_document(&html_str);
    // Convert to array of all elements with tag, text, attrs
    let mut elements = Vec::new();
    for node in doc.tree.nodes() {
        if let Some(el) = node.value().as_element() {
            let tag = el.name().to_string();
            let mut attrs = indexmap::IndexMap::new();
            for (k, v) in el.attrs() {
                attrs.insert(k.to_string(), PerlValue::string(v.to_string()));
            }
            // Get direct text content
            let text: String = node
                .children()
                .filter_map(|c| c.value().as_text().map(|t| t.text.to_string()))
                .collect::<Vec<_>>()
                .join("");
            let mut h = indexmap::IndexMap::new();
            h.insert("tag".into(), PerlValue::string(tag));
            if !text.trim().is_empty() {
                h.insert("text".into(), PerlValue::string(text.trim().to_string()));
            }
            if !attrs.is_empty() {
                h.insert(
                    "attrs".into(),
                    PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(attrs))),
                );
            }
            elements.push(PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))));
        }
    }
    Ok(PerlValue::array(elements))
}

/// `css_select SELECTOR, HTML_STRING` — query HTML with CSS selector, return matching elements.
/// Each element is a hashref {tag, text, attrs, html}.
fn builtin_css_select(
    interp: &Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    let selector_str = args.first().map(|v| v.to_string()).unwrap_or_default();
    let html_str = if args.len() > 1 {
        args[1].to_string()
    } else {
        first_arg_or_topic(interp, &[]).to_string()
    };
    let doc = scraper::Html::parse_document(&html_str);
    let selector = scraper::Selector::parse(&selector_str).map_err(|_| {
        PerlError::runtime(
            format!("css_select: invalid selector: {}", selector_str),
            line,
        )
    })?;
    let mut result = Vec::new();
    for el in doc.select(&selector) {
        let mut h = indexmap::IndexMap::new();
        h.insert(
            "tag".into(),
            PerlValue::string(el.value().name().to_string()),
        );
        let text = el.text().collect::<Vec<_>>().join("");
        if !text.trim().is_empty() {
            h.insert("text".into(), PerlValue::string(text.trim().to_string()));
        }
        let mut attrs = indexmap::IndexMap::new();
        for (k, v) in el.value().attrs() {
            attrs.insert(k.to_string(), PerlValue::string(v.to_string()));
        }
        if !attrs.is_empty() {
            h.insert(
                "attrs".into(),
                PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(attrs))),
            );
        }
        h.insert("html".into(), PerlValue::string(el.inner_html()));
        result.push(PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))));
    }
    Ok(PerlValue::array(result))
}

/// `xml_parse XML_STRING` — parse XML into a nested hashref tree.
fn builtin_xml_parse(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let xml_str = args.first().map(|v| v.to_string()).unwrap_or_default();
    let doc = roxmltree::Document::parse(&xml_str)
        .map_err(|e| PerlError::runtime(format!("xml_parse: {}", e), line))?;
    fn node_to_perl(node: roxmltree::Node) -> PerlValue {
        if node.is_text() {
            return PerlValue::string(node.text().unwrap_or("").to_string());
        }
        if !node.is_element() {
            return PerlValue::UNDEF;
        }
        let mut h = indexmap::IndexMap::new();
        h.insert(
            "tag".to_string(),
            PerlValue::string(node.tag_name().name().to_string()),
        );
        // Attributes
        let mut attrs = indexmap::IndexMap::new();
        for attr in node.attributes() {
            attrs.insert(
                attr.name().to_string(),
                PerlValue::string(attr.value().to_string()),
            );
        }
        if !attrs.is_empty() {
            h.insert(
                "attrs".to_string(),
                PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(attrs))),
            );
        }
        // Text content
        let text: String = node
            .children()
            .filter(|c| c.is_text())
            .filter_map(|c| c.text())
            .collect::<Vec<_>>()
            .join("");
        if !text.trim().is_empty() {
            h.insert(
                "text".to_string(),
                PerlValue::string(text.trim().to_string()),
            );
        }
        // Child elements
        let children: Vec<PerlValue> = node
            .children()
            .filter(|c| c.is_element())
            .map(node_to_perl)
            .collect();
        if !children.is_empty() {
            h.insert("children".to_string(), PerlValue::array(children));
        }
        PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(h)))
    }
    Ok(node_to_perl(doc.root_element()))
}

/// `xpath EXPR, XML_STRING` — query XML with simple XPath-like expressions.
/// Supports: `//tag`, `//tag[@attr]`, `//tag[@attr='val']`, `/root/child`.
fn builtin_xpath(interp: &Interpreter, args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let xpath_str = args.first().map(|v| v.to_string()).unwrap_or_default();
    let xml_str = if args.len() > 1 {
        args[1].to_string()
    } else {
        first_arg_or_topic(interp, &[]).to_string()
    };
    let doc = roxmltree::Document::parse(&xml_str)
        .map_err(|e| PerlError::runtime(format!("xpath: {}", e), line))?;

    // Simple xpath: extract tag name and optional attr filter
    let _search_all = xpath_str.starts_with("//");
    let path = xpath_str.trim_start_matches('/');
    // Parse "tag[@attr='val']" or "tag[@attr]" or just "tag"
    let (tag, attr_name, attr_val) = if let Some(bracket) = path.find('[') {
        let tag = &path[..bracket];
        let inside = path[bracket + 1..].trim_end_matches(']');
        let inside = inside.trim_start_matches('@');
        if let Some(eq) = inside.find('=') {
            let aname = &inside[..eq];
            let aval = inside[eq + 1..].trim_matches('\'').trim_matches('"');
            (tag, Some(aname.to_string()), Some(aval.to_string()))
        } else {
            (tag, Some(inside.to_string()), None)
        }
    } else {
        (path, None, None)
    };

    fn collect_matching(
        node: roxmltree::Node,
        tag: &str,
        attr_name: &Option<String>,
        attr_val: &Option<String>,
        result: &mut Vec<PerlValue>,
    ) {
        if node.is_element() && node.tag_name().name() == tag {
            let matches = match (attr_name, attr_val) {
                (Some(an), Some(av)) => node.attribute(an.as_str()) == Some(av.as_str()),
                (Some(an), None) => node.has_attribute(an.as_str()),
                _ => true,
            };
            if matches {
                let mut h = indexmap::IndexMap::new();
                h.insert("tag".to_string(), PerlValue::string(tag.to_string()));
                let text: String = node
                    .descendants()
                    .filter(|c| c.is_text())
                    .filter_map(|c| c.text())
                    .collect::<Vec<_>>()
                    .join("");
                if !text.trim().is_empty() {
                    h.insert(
                        "text".to_string(),
                        PerlValue::string(text.trim().to_string()),
                    );
                }
                let mut attrs = indexmap::IndexMap::new();
                for attr in node.attributes() {
                    attrs.insert(
                        attr.name().to_string(),
                        PerlValue::string(attr.value().to_string()),
                    );
                }
                if !attrs.is_empty() {
                    h.insert(
                        "attrs".to_string(),
                        PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(attrs))),
                    );
                }
                result.push(PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))));
            }
        }
        for child in node.children() {
            collect_matching(child, tag, attr_name, attr_val, result);
        }
    }

    let mut result = Vec::new();
    collect_matching(doc.root_element(), tag, &attr_name, &attr_val, &mut result);
    Ok(PerlValue::array(result))
}

/// `smtp_send OPTIONS` — send email via SMTP. OPTIONS is a hashref:
/// {to, from, subject, body, smtp_host, smtp_port, smtp_user, smtp_pass}
/// smtp_host defaults to "smtp.gmail.com", smtp_port to 587.
fn builtin_smtp_send(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    use lettre::transport::smtp::authentication::Credentials;
    use lettre::{Message, SmtpTransport, Transport};

    let opts = args.first().and_then(|v| v.as_hash_ref()).ok_or_else(|| {
        PerlError::runtime(
            "smtp_send: argument must be a hashref with {to, from, subject, body, ...}",
            line,
        )
    })?;
    let opts = opts.read();

    let to = opts
        .get("to")
        .map(|v| v.to_string())
        .ok_or_else(|| PerlError::runtime("smtp_send: missing 'to'", line))?;
    let from = opts
        .get("from")
        .map(|v| v.to_string())
        .ok_or_else(|| PerlError::runtime("smtp_send: missing 'from'", line))?;
    let subject = opts
        .get("subject")
        .map(|v| v.to_string())
        .unwrap_or_default();
    let body = opts.get("body").map(|v| v.to_string()).unwrap_or_default();
    let host = opts
        .get("smtp_host")
        .map(|v| v.to_string())
        .unwrap_or_else(|| "smtp.gmail.com".into());
    let user = opts
        .get("smtp_user")
        .map(|v| v.to_string())
        .unwrap_or_else(|| from.clone());
    let pass = opts
        .get("smtp_pass")
        .map(|v| v.to_string())
        .ok_or_else(|| PerlError::runtime("smtp_send: missing 'smtp_pass'", line))?;

    let email = Message::builder()
        .from(
            from.parse()
                .map_err(|e| PerlError::runtime(format!("smtp_send: invalid from: {}", e), line))?,
        )
        .to(to
            .parse()
            .map_err(|e| PerlError::runtime(format!("smtp_send: invalid to: {}", e), line))?)
        .subject(subject)
        .body(body)
        .map_err(|e| PerlError::runtime(format!("smtp_send: {}", e), line))?;

    let creds = Credentials::new(user, pass);
    let mailer = SmtpTransport::starttls_relay(&host)
        .map_err(|e| PerlError::runtime(format!("smtp_send: {}", e), line))?
        .credentials(creds)
        .build();

    mailer
        .send(&email)
        .map_err(|e| PerlError::runtime(format!("smtp_send: {}", e), line))?;

    Ok(PerlValue::integer(1))
}

fn builtin_pdf_text(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    let bytes = std::fs::read(&path)
        .map_err(|e| PerlError::runtime(format!("pdf_text: {}: {}", path, e), line))?;
    let text = pdf_extract::extract_text_from_mem(&bytes)
        .map_err(|e| PerlError::runtime(format!("pdf_text: {}: {}", path, e), line))?;
    Ok(PerlValue::string(text))
}

/// `pdf_pages FILE` — return number of pages in a PDF (counts page-break markers in extracted text).
fn builtin_pdf_pages(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    let bytes = std::fs::read(&path)
        .map_err(|e| PerlError::runtime(format!("pdf_pages: {}: {}", path, e), line))?;
    let text = pdf_extract::extract_text_from_mem(&bytes)
        .map_err(|e| PerlError::runtime(format!("pdf_pages: {}: {}", path, e), line))?;
    // pdf-extract inserts form-feed (\x0c) between pages
    let pages = text.matches('\x0c').count() + 1;
    Ok(PerlValue::integer(pages as i64))
}

fn svg_to_pdf(svg_str: &str, line: usize) -> PerlResult<Vec<u8>> {
    let opts = svg2pdf::usvg::Options::default();
    let tree = svg2pdf::usvg::Tree::from_str(svg_str, &opts)
        .map_err(|e| PerlError::runtime(format!("to_pdf: SVG parse error: {}", e), line))?;
    let pdf = svg2pdf::to_pdf(
        &tree,
        svg2pdf::ConversionOptions::default(),
        svg2pdf::PageOptions::default(),
    )
    .map_err(|e| PerlError::runtime(format!("to_pdf: SVG conversion error: {}", e), line))?;
    Ok(pdf)
}

/// `audio_convert INPUT, OUTPUT` — convert WAV/FLAC/AIFF to MP3 (or WAV).
/// Uses symphonia for decoding and mp3lame-encoder for MP3 encoding.
fn builtin_audio_convert(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    use symphonia::core::audio::SampleBuffer;
    use symphonia::core::codecs::DecoderOptions;
    use symphonia::core::formats::FormatOptions;
    use symphonia::core::io::MediaSourceStream;
    use symphonia::core::meta::MetadataOptions;
    use symphonia::core::probe::Hint;

    let input_path = args.first().map(|v| v.to_string()).unwrap_or_default();
    let output_path = args.get(1).map(|v| v.to_string()).unwrap_or_default();
    if input_path.is_empty() || output_path.is_empty() {
        return Err(PerlError::runtime(
            "audio_convert: need INPUT and OUTPUT paths",
            line,
        ));
    }

    // Open input
    let file = std::fs::File::open(&input_path)
        .map_err(|e| PerlError::runtime(format!("audio_convert: {}: {}", input_path, e), line))?;
    let mss = MediaSourceStream::new(Box::new(file), Default::default());
    let mut hint = Hint::new();
    if let Some(ext) = std::path::Path::new(&input_path)
        .extension()
        .and_then(|e| e.to_str())
    {
        hint.with_extension(ext);
    }
    let probed = symphonia::default::get_probe()
        .format(
            &hint,
            mss,
            &FormatOptions::default(),
            &MetadataOptions::default(),
        )
        .map_err(|e| PerlError::runtime(format!("audio_convert: probe: {}", e), line))?;

    let mut format = probed.format;
    let track = format
        .default_track()
        .ok_or_else(|| PerlError::runtime("audio_convert: no audio track found", line))?;
    let track_id = track.id;
    let channels = track.codec_params.channels.map(|c| c.count()).unwrap_or(2) as u32;
    let sample_rate = track.codec_params.sample_rate.unwrap_or(44100);

    let mut decoder = symphonia::default::get_codecs()
        .make(&track.codec_params, &DecoderOptions::default())
        .map_err(|e| PerlError::runtime(format!("audio_convert: decoder: {}", e), line))?;

    // Decode all samples to interleaved i16
    let mut all_samples: Vec<i16> = Vec::new();
    loop {
        let packet = match format.next_packet() {
            Ok(p) => p,
            Err(symphonia::core::errors::Error::IoError(ref e))
                if e.kind() == std::io::ErrorKind::UnexpectedEof =>
            {
                break
            }
            Err(_) => break,
        };
        if packet.track_id() != track_id {
            continue;
        }
        let decoded = match decoder.decode(&packet) {
            Ok(d) => d,
            Err(_) => continue,
        };
        let spec = *decoded.spec();
        let n_frames = decoded.frames();
        let mut sample_buf = SampleBuffer::<i16>::new(n_frames as u64, spec);
        sample_buf.copy_interleaved_ref(decoded);
        all_samples.extend_from_slice(sample_buf.samples());
    }

    if all_samples.is_empty() {
        return Err(PerlError::runtime(
            "audio_convert: no audio data decoded",
            line,
        ));
    }

    let out_ext = std::path::Path::new(&output_path)
        .extension()
        .and_then(|e| e.to_str())
        .unwrap_or("mp3")
        .to_lowercase();

    match out_ext.as_str() {
        "mp3" => {
            use mp3lame_encoder::{Builder, FlushNoGap, InterleavedPcm};
            let mut builder = Builder::new().ok_or_else(|| {
                PerlError::runtime("audio_convert: mp3 encoder init failed", line)
            })?;
            builder
                .set_num_channels(channels as u8)
                .map_err(|e| PerlError::runtime(format!("audio_convert: mp3: {:?}", e), line))?;
            builder
                .set_sample_rate(sample_rate)
                .map_err(|e| PerlError::runtime(format!("audio_convert: mp3: {:?}", e), line))?;
            builder
                .set_brate(mp3lame_encoder::Bitrate::Kbps192)
                .map_err(|e| PerlError::runtime(format!("audio_convert: mp3: {:?}", e), line))?;
            builder
                .set_quality(mp3lame_encoder::Quality::Best)
                .map_err(|e| PerlError::runtime(format!("audio_convert: mp3: {:?}", e), line))?;
            let mut encoder = builder.build().map_err(|e| {
                PerlError::runtime(format!("audio_convert: mp3 build: {:?}", e), line)
            })?;
            let input = InterleavedPcm(&all_samples);
            let mut mp3_out = Vec::with_capacity(all_samples.len());
            encoder
                .encode_to_vec(input, &mut mp3_out)
                .map_err(|e| PerlError::runtime(format!("audio_convert: encode: {:?}", e), line))?;
            encoder
                .flush_to_vec::<FlushNoGap>(&mut mp3_out)
                .map_err(|e| PerlError::runtime(format!("audio_convert: flush: {:?}", e), line))?;
            std::fs::write(&output_path, &mp3_out)
                .map_err(|e| PerlError::runtime(format!("audio_convert: write: {}", e), line))?;
        }
        "wav" => {
            // Write raw WAV using simple header
            let data_len = (all_samples.len() * 2) as u32;
            let file_len = 36 + data_len;
            let byte_rate = sample_rate * channels * 2;
            let block_align = channels as u16 * 2;
            let mut wav = Vec::with_capacity(file_len as usize + 8);
            wav.extend_from_slice(b"RIFF");
            wav.extend_from_slice(&file_len.to_le_bytes());
            wav.extend_from_slice(b"WAVEfmt ");
            wav.extend_from_slice(&16u32.to_le_bytes()); // chunk size
            wav.extend_from_slice(&1u16.to_le_bytes()); // PCM
            wav.extend_from_slice(&(channels as u16).to_le_bytes());
            wav.extend_from_slice(&sample_rate.to_le_bytes());
            wav.extend_from_slice(&byte_rate.to_le_bytes());
            wav.extend_from_slice(&block_align.to_le_bytes());
            wav.extend_from_slice(&16u16.to_le_bytes()); // bits per sample
            wav.extend_from_slice(b"data");
            wav.extend_from_slice(&data_len.to_le_bytes());
            for &s in &all_samples {
                wav.extend_from_slice(&s.to_le_bytes());
            }
            std::fs::write(&output_path, &wav)
                .map_err(|e| PerlError::runtime(format!("audio_convert: write: {}", e), line))?;
        }
        _ => {
            return Err(PerlError::runtime(
                format!(
                    "audio_convert: unsupported output format '.{}' (use .mp3 or .wav)",
                    out_ext
                ),
                line,
            ))
        }
    }

    Ok(PerlValue::string(output_path))
}

/// `audio_info FILE` — return audio file metadata as hashref.
fn builtin_audio_info(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    use symphonia::core::formats::FormatOptions;
    use symphonia::core::io::MediaSourceStream;
    use symphonia::core::meta::MetadataOptions;
    use symphonia::core::probe::Hint;

    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    let file = std::fs::File::open(&path)
        .map_err(|e| PerlError::runtime(format!("audio_info: {}: {}", path, e), line))?;
    let mss = MediaSourceStream::new(Box::new(file), Default::default());
    let mut hint = Hint::new();
    if let Some(ext) = std::path::Path::new(&path)
        .extension()
        .and_then(|e| e.to_str())
    {
        hint.with_extension(ext);
    }
    let probed = symphonia::default::get_probe()
        .format(
            &hint,
            mss,
            &FormatOptions::default(),
            &MetadataOptions::default(),
        )
        .map_err(|e| PerlError::runtime(format!("audio_info: {}", e), line))?;

    let format = probed.format;
    let mut h = indexmap::IndexMap::new();
    h.insert("path".to_string(), PerlValue::string(path));

    if let Some(track) = format.default_track() {
        let params = &track.codec_params;
        if let Some(sr) = params.sample_rate {
            h.insert("sample_rate".to_string(), PerlValue::integer(sr as i64));
        }
        if let Some(ch) = params.channels {
            h.insert(
                "channels".to_string(),
                PerlValue::integer(ch.count() as i64),
            );
        }
        if let Some(n) = params.n_frames {
            h.insert("frames".to_string(), PerlValue::integer(n as i64));
            if let Some(sr) = params.sample_rate {
                let duration = n as f64 / sr as f64;
                h.insert("duration_secs".to_string(), PerlValue::float(duration));
            }
        }
        if let Some(bps) = params.bits_per_sample {
            h.insert(
                "bits_per_sample".to_string(),
                PerlValue::integer(bps as i64),
            );
        }
    }

    Ok(PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))))
}

/// `id3_read FILE` — read ID3 tags from an MP3 file, return as hashref.
fn builtin_id3_read(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    use id3::TagLike;
    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    let tag = id3::Tag::read_from_path(&path)
        .map_err(|e| PerlError::runtime(format!("id3_read: {}: {}", path, e), line))?;
    let mut h = indexmap::IndexMap::new();
    if let Some(v) = tag.title() {
        h.insert("title".into(), PerlValue::string(v.to_string()));
    }
    if let Some(v) = tag.artist() {
        h.insert("artist".into(), PerlValue::string(v.to_string()));
    }
    if let Some(v) = tag.album() {
        h.insert("album".into(), PerlValue::string(v.to_string()));
    }
    if let Some(v) = tag.year() {
        h.insert("year".into(), PerlValue::integer(v as i64));
    }
    if let Some(v) = tag.track() {
        h.insert("track".into(), PerlValue::integer(v as i64));
    }
    if let Some(v) = tag.genre_parsed() {
        h.insert("genre".into(), PerlValue::string(v.to_string()));
    }
    if let Some(v) = tag.album_artist() {
        h.insert("album_artist".into(), PerlValue::string(v.to_string()));
    }
    if let Some(v) = tag.disc() {
        h.insert("disc".into(), PerlValue::integer(v as i64));
    }
    if let Some(v) = tag.duration() {
        h.insert("duration_secs".into(), PerlValue::integer(v as i64));
    }
    // Collect all comments
    let comments: Vec<PerlValue> = tag
        .comments()
        .map(|c| PerlValue::string(c.text.clone()))
        .collect();
    if !comments.is_empty() {
        h.insert("comments".into(), PerlValue::array(comments));
    }
    Ok(PerlValue::hash_ref(Arc::new(parking_lot::RwLock::new(h))))
}

/// `id3_write FILE, TAGS` — write ID3 tags to an MP3 file.
/// TAGS is a hashref: {title => "...", artist => "...", album => "...", year => N, track => N, genre => "..."}
fn builtin_id3_write(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    use id3::TagLike;
    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    let tags_val = args.get(1).cloned().unwrap_or(PerlValue::UNDEF);
    let tags_hr = tags_val
        .as_hash_ref()
        .ok_or_else(|| PerlError::runtime("id3_write: second arg must be a hashref", line))?;
    let tags = tags_hr.read();
    let mut tag = id3::Tag::read_from_path(&path).unwrap_or_else(|_| id3::Tag::new());
    if let Some(v) = tags.get("title") {
        tag.set_title(v.to_string());
    }
    if let Some(v) = tags.get("artist") {
        tag.set_artist(v.to_string());
    }
    if let Some(v) = tags.get("album") {
        tag.set_album(v.to_string());
    }
    if let Some(v) = tags.get("year") {
        tag.set_year(v.to_int() as i32);
    }
    if let Some(v) = tags.get("track") {
        tag.set_track(v.to_int() as u32);
    }
    if let Some(v) = tags.get("genre") {
        tag.set_genre(v.to_string());
    }
    if let Some(v) = tags.get("album_artist") {
        tag.set_album_artist(v.to_string());
    }
    if let Some(v) = tags.get("disc") {
        tag.set_disc(v.to_int() as u32);
    }
    drop(tags);
    tag.write_to_path(&path, id3::Version::Id3v24)
        .map_err(|e| PerlError::runtime(format!("id3_write: {}: {}", path, e), line))?;
    Ok(PerlValue::string(path))
}

/// Convert PerlValue content into lines of text for PDF rendering.
fn pdf_content_to_lines(val: &PerlValue) -> Vec<String> {
    if val.is_undef() {
        return vec!["(undef)".to_string()];
    }

    let s = val.to_string();

    // Hashref → key: value lines
    if let Some(hr) = val.as_hash_ref() {
        let guard = hr.read();
        let mut lines = Vec::new();
        let max_key = guard.keys().map(|k| k.len()).max().unwrap_or(0);
        for (k, v) in guard.iter() {
            lines.push(format!("{:width$}  {}", k, v, width = max_key));
        }
        return lines;
    }

    // Array of hashrefs → table
    if let Some(ar) = val.as_array_ref() {
        let guard = ar.read();
        if !guard.is_empty() {
            // Check if first element is a hashref (tabular data)
            if guard[0].as_hash_ref().is_some() {
                let mut headers: Vec<String> = Vec::new();
                for item in guard.iter() {
                    if let Some(hr) = item.as_hash_ref() {
                        for k in hr.read().keys() {
                            if !headers.contains(k) {
                                headers.push(k.clone());
                            }
                        }
                    }
                }
                let col_widths: Vec<usize> = headers
                    .iter()
                    .map(|h| {
                        let data_max = guard
                            .iter()
                            .filter_map(|item| {
                                item.as_hash_ref()
                                    .and_then(|hr| hr.read().get(h).map(|v| v.to_string().len()))
                            })
                            .max()
                            .unwrap_or(0);
                        h.len().max(data_max).min(30)
                    })
                    .collect();
                let mut lines = Vec::new();
                // Header
                let header: String = headers
                    .iter()
                    .enumerate()
                    .map(|(i, h)| format!("{:width$}", h, width = col_widths[i]))
                    .collect::<Vec<_>>()
                    .join("  ");
                lines.push(header);
                lines.push(
                    col_widths
                        .iter()
                        .map(|&w| "-".repeat(w))
                        .collect::<Vec<_>>()
                        .join("  "),
                );
                // Rows
                for item in guard.iter() {
                    if let Some(hr) = item.as_hash_ref() {
                        let rg = hr.read();
                        let row: String = headers
                            .iter()
                            .enumerate()
                            .map(|(i, h)| {
                                let v = rg.get(h).map(|v| v.to_string()).unwrap_or_default();
                                let truncated = if v.len() > col_widths[i] {
                                    format!("{}…", &v[..col_widths[i] - 1])
                                } else {
                                    v
                                };
                                format!("{:width$}", truncated, width = col_widths[i])
                            })
                            .collect::<Vec<_>>()
                            .join("  ");
                        lines.push(row);
                    }
                }
                return lines;
            }
            // Plain array → one line per element
            return guard.iter().map(|v| v.to_string()).collect();
        }
    }

    // Plain text → split on newlines
    s.lines().map(|l| l.to_string()).collect()
}

/// Generate a minimal valid PDF from text lines. Pure Rust, no crate.
/// Uses Courier (monospace) font, A4 page size, cyberpunk-ish dark header.
fn generate_pdf(lines: &[String]) -> Vec<u8> {
    let page_w = 595.0_f64; // A4 width in points
    let page_h = 842.0_f64; // A4 height
    let margin = 50.0;
    let font_size = 9.0;
    let line_height = 12.0;
    let usable_h = page_h - margin * 2.0;
    let lines_per_page = (usable_h / line_height) as usize;

    let pages: Vec<&[String]> = lines.chunks(lines_per_page).collect();
    let n_pages = pages.len().max(1);

    let mut buf = Vec::with_capacity(4096);
    let mut offsets: Vec<usize> = Vec::new();

    // Header
    buf.extend_from_slice(b"%PDF-1.4\n%\xe2\xe3\xcf\xd3\n");

    // Object 1: Catalog
    offsets.push(buf.len());
    buf.extend_from_slice(b"1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n");

    // Object 2: Pages
    offsets.push(buf.len());
    let mut pages_kids = String::from("2 0 obj\n<< /Type /Pages /Kids [");
    for i in 0..n_pages {
        if i > 0 {
            pages_kids.push(' ');
        }
        pages_kids.push_str(&format!("{} 0 R", 4 + i * 2));
    }
    pages_kids.push_str(&format!("] /Count {} >>\nendobj\n", n_pages));
    buf.extend_from_slice(pages_kids.as_bytes());

    // Object 3: Font
    offsets.push(buf.len());
    buf.extend_from_slice(
        b"3 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Courier >>\nendobj\n",
    );

    // Page objects (each page = page_obj + stream_obj)
    for (pi, page_lines) in pages.iter().enumerate() {
        let page_obj_num = 4 + pi * 2;
        let stream_obj_num = 5 + pi * 2;

        // Build content stream
        let mut stream = String::with_capacity(1024);
        // Dark header bar
        stream.push_str(&format!(
            "0.02 0.02 0.04 rg\n0 {} {} {} re f\n",
            page_h - 35.0,
            page_w,
            35.0
        ));
        // Header text "STRYKE" in cyan-ish
        stream.push_str("BT\n0.02 0.85 0.91 rg\n/F1 11 Tf\n");
        stream.push_str(&format!(
            "{} {} Td\n(STRYKE) Tj\nET\n",
            margin,
            page_h - 25.0
        ));
        // Page number
        stream.push_str("BT\n0.5 0.5 0.6 rg\n/F1 8 Tf\n");
        stream.push_str(&format!(
            "{} {} Td\n(Page {} of {}) Tj\nET\n",
            page_w - margin - 60.0,
            page_h - 25.0,
            pi + 1,
            n_pages
        ));

        // Body text
        stream.push_str(&format!("BT\n0.1 0.1 0.15 rg\n/F1 {} Tf\n", font_size));
        let mut y = page_h - margin - 20.0;
        for text_line in *page_lines {
            // Escape PDF special chars
            let escaped = text_line
                .replace('\\', "\\\\")
                .replace('(', "\\(")
                .replace(')', "\\)");
            stream.push_str(&format!(
                "{} {} Td\n({}) Tj\n0 {} Td\n",
                margin, y, escaped, -line_height
            ));
            y = 0.0; // After first Td, use relative positioning
        }
        stream.push_str("ET\n");

        // Footer line
        stream.push_str(&format!(
            "0.1 0.1 0.2 rg\n{} 30 m {} 30 l 0.5 w S\n",
            margin,
            page_w - margin
        ));

        let stream_bytes = stream.as_bytes();

        // Page object
        offsets.push(buf.len());
        let page_dict = format!(
            "{} 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 {} {}] /Contents {} 0 R /Resources << /Font << /F1 3 0 R >> >> >>\nendobj\n",
            page_obj_num, page_w, page_h, stream_obj_num
        );
        buf.extend_from_slice(page_dict.as_bytes());

        // Stream object
        offsets.push(buf.len());
        let stream_header = format!(
            "{} 0 obj\n<< /Length {} >>\nstream\n",
            stream_obj_num,
            stream_bytes.len()
        );
        buf.extend_from_slice(stream_header.as_bytes());
        buf.extend_from_slice(stream_bytes);
        buf.extend_from_slice(b"\nendstream\nendobj\n");
    }

    // Cross-reference table
    let xref_offset = buf.len();
    let n_objects = offsets.len() + 1; // +1 for object 0
    buf.extend_from_slice(format!("xref\n0 {}\n", n_objects).as_bytes());
    buf.extend_from_slice(b"0000000000 65535 f \n");
    for &off in &offsets {
        buf.extend_from_slice(format!("{:010} 00000 n \n", off).as_bytes());
    }

    // Trailer
    buf.extend_from_slice(
        format!(
            "trailer\n<< /Size {} /Root 1 0 R >>\nstartxref\n{}\n%%EOF\n",
            n_objects, xref_offset
        )
        .as_bytes(),
    );

    buf
}

fn ddump_value(buf: &mut String, val: &PerlValue, depth: usize) {
    use std::fmt::Write;
    let indent = "  ".repeat(depth);
    let inner = "  ".repeat(depth + 1);

    if val.is_undef() {
        buf.push_str("undef");
        return;
    }

    if let Some(ar) = val.as_array_ref() {
        let guard = ar.read();
        if guard.is_empty() {
            buf.push_str("[]");
            return;
        }
        buf.push_str("[\n");
        for (i, elem) in guard.iter().enumerate() {
            buf.push_str(&inner);
            ddump_value(buf, elem, depth + 1);
            if i + 1 < guard.len() {
                buf.push(',');
            }
            buf.push('\n');
        }
        buf.push_str(&indent);
        buf.push(']');
        return;
    }

    if let Some(hr) = val.as_hash_ref() {
        let guard = hr.read();
        if guard.is_empty() {
            buf.push_str("{}");
            return;
        }
        buf.push_str("{\n");
        let len = guard.len();
        for (i, (k, v)) in guard.iter().enumerate() {
            buf.push_str(&inner);
            let _ = write!(buf, "'{k}' => ");
            ddump_value(buf, v, depth + 1);
            if i + 1 < len {
                buf.push(',');
            }
            buf.push('\n');
        }
        buf.push_str(&indent);
        buf.push('}');
        return;
    }

    if let Some(sr) = val.as_scalar_ref() {
        let inner_val = sr.read().clone();
        buf.push('\\');
        ddump_value(buf, &inner_val, depth);
        return;
    }

    if let Some(s) = val.as_struct_inst() {
        let _ = writeln!(buf, "{}(", s.def.name);
        let values = s.get_values();
        for (i, field) in s.def.fields.iter().enumerate() {
            buf.push_str(&inner);
            let _ = write!(buf, "{} => ", field.name);
            ddump_value(buf, &values[i], depth + 1);
            if i + 1 < s.def.fields.len() {
                buf.push(',');
            }
            buf.push('\n');
        }
        buf.push_str(&indent);
        buf.push(')');
        return;
    }

    if let Some(blessed) = val.as_blessed_ref() {
        let data = blessed.data.read().clone();
        let _ = write!(buf, "bless(");
        ddump_value(buf, &data, depth);
        let _ = write!(buf, ", '{}')", blessed.class);
        return;
    }

    // Numeric (int or float) — print bare
    if val.is_integer_like() || val.is_float_like() {
        let _ = write!(buf, "{val}");
        return;
    }

    // String — quote it
    let s = val.to_string();
    let escaped = s.replace('\\', "\\\\").replace('\'', "\\'");
    let _ = write!(buf, "'{escaped}'");
}

/// `read_lines PATH` — slurp file into array of chomped lines.
fn builtin_read_lines(
    interp: &Interpreter,
    args: &[PerlValue],
    line: usize,
) -> PerlResult<PerlValue> {
    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    let content = std::fs::read_to_string(&path)
        .map_err(|e| PerlError::runtime(format!("read_lines: {}: {}", path, e), line))?;
    let lines: Vec<PerlValue> = content
        .lines()
        .map(|l| PerlValue::string(l.to_string()))
        .collect();
    Ok(match interp.wantarray_kind {
        WantarrayCtx::List => PerlValue::array(lines),
        WantarrayCtx::Scalar => PerlValue::integer(lines.len() as i64),
        WantarrayCtx::Void => PerlValue::UNDEF,
    })
}

/// `append_file PATH, DATA` — append content to a file.
fn builtin_append_file(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    if args.len() < 2 {
        return Err(PerlError::runtime("append_file needs PATH and DATA", line));
    }
    let path = args[0].to_string();
    let data = perl_scalar_as_bytes(&args[1]);
    use std::io::Write;
    let mut f = std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(&path)
        .map_err(|e| PerlError::runtime(format!("append_file: {}: {}", path, e), line))?;
    f.write_all(&data)
        .map_err(|e| PerlError::runtime(format!("append_file: {}: {}", path, e), line))?;
    Ok(PerlValue::integer(data.len() as i64))
}

/// `tempfile()` or `tempfile(SUFFIX)` — create a temporary file, return its path.
fn builtin_tempfile(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let suffix = args.first().map(|v| v.to_string()).unwrap_or_default();
    let dir = std::env::temp_dir();
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos();
    let name = if suffix.is_empty() {
        format!("stryke_tmp_{}", stamp)
    } else {
        format!("stryke_tmp_{}{}", stamp, suffix)
    };
    let path = dir.join(name);
    std::fs::File::create(&path)
        .map_err(|e| PerlError::runtime(format!("tempfile: {}", e), line))?;
    Ok(PerlValue::string(path.to_string_lossy().to_string()))
}

/// `tempdir()` — create a temporary directory, return its path.
fn builtin_tempdir(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let suffix = args.first().map(|v| v.to_string()).unwrap_or_default();
    let dir = std::env::temp_dir();
    let stamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos();
    let name = if suffix.is_empty() {
        format!("stryke_tmpd_{}", stamp)
    } else {
        format!("stryke_tmpd_{}{}", stamp, suffix)
    };
    let path = dir.join(name);
    std::fs::create_dir_all(&path)
        .map_err(|e| PerlError::runtime(format!("tempdir: {}", e), line))?;
    Ok(PerlValue::string(path.to_string_lossy().to_string()))
}

/// `read_json PATH` — read a JSON file and decode into a Perl value.
fn builtin_read_json(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    let path = args.first().map(|v| v.to_string()).unwrap_or_default();
    let content = std::fs::read_to_string(&path)
        .map_err(|e| PerlError::runtime(format!("read_json: {}: {}", path, e), line))?;
    crate::native_data::json_decode(&content)
}

/// `write_json PATH, VALUE` — encode value as JSON and write to file.
fn builtin_write_json(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    if args.len() < 2 {
        return Err(PerlError::runtime("write_json needs PATH and VALUE", line));
    }
    let path = args[0].to_string();
    let val = &args[1];
    let json = crate::native_data::json_encode(val)?;
    let s = json.to_string();
    std::fs::write(&path, s.as_bytes())
        .map_err(|e| PerlError::runtime(format!("write_json: {}: {}", path, e), line))?;
    Ok(PerlValue::integer(s.len() as i64))
}

/// `glob_match PATTERN, STRING` — test if STRING matches a glob pattern.
fn builtin_glob_match(args: &[PerlValue], line: usize) -> PerlResult<PerlValue> {
    if args.len() < 2 {
        return Err(PerlError::runtime(
            "glob_match needs PATTERN and STRING",
            line,
        ));
    }
    let pattern = args[0].to_string();
    let target = args[1].to_string();
    // Simple glob matching: * matches anything, ? matches one char
    let re_str = glob_pattern_to_regex(&pattern);
    let matched = regex::Regex::new(&re_str)
        .map(|re| re.is_match(&target))
        .unwrap_or(false);
    Ok(PerlValue::integer(matched as i64))
}

/// Convert a glob pattern to a regex string.
fn glob_pattern_to_regex(pattern: &str) -> String {
    let mut re = String::from("^");
    let mut chars = pattern.chars().peekable();
    while let Some(c) = chars.next() {
        match c {
            '*' => {
                if chars.peek() == Some(&'*') {
                    chars.next();
                    re.push_str(".*");
                } else {
                    re.push_str("[^/]*");
                }
            }
            '?' => re.push('.'),
            '.' | '+' | '(' | ')' | '{' | '}' | '[' | ']' | '^' | '$' | '|' | '\\' => {
                re.push('\\');
                re.push(c);
            }
            _ => re.push(c),
        }
    }
    re.push('$');
    re
}

